    {"id": 43, "unit": "Unit 1", "unitName": "Foundations of American Democracy", "concept": "Devolution", "question": "Devolution refers to:", "options": ["Increasing federal power over the states", "Eliminating state governments", "Transferring power from the federal government to state and local governments", "Combining the legislative and executive branches"], "answer": "C", "explanation": "Devolution shifts responsibilities and authority from Washington to the states."},
    {"id": 44, "unit": "Unit 1", "unitName": "Foundations of American Democracy", "concept": "Privileges and Immunities Clause", "question": "The Privileges and Immunities Clause prevents states from:", "options": ["Passing any laws", "Discriminating against citizens of other states in fundamental rights", "Collecting sales tax from visitors", "Holding elections"], "answer": "B", "explanation": "States cannot deny fundamental rights to out-of-state citizens."},
    {"id": 45, "unit": "Unit 1", "unitName": "Foundations of American Democracy", "concept": "Article V", "question": "What fraction of state legislatures must ratify a proposed amendment?", "options": ["One-half", "Three-fourths", "Two-thirds", "Four-fifths"], "answer": "B", "explanation": "Three-fourths (38 of 50) of state legislatures must ratify an amendment."},
    {"id": 46, "unit": "Unit 1", "unitName": "Foundations of American Democracy", "concept": "Hobbes vs. Locke", "question": "Thomas Hobbes and John Locke agreed that:", "options": ["Government should be a monarchy", "Revolution is always justified", "Rights are not natural", "People form governments through a social contract"], "answer": "D", "explanation": "Both believed in the social contract, though they disagreed on government's nature."},
    {"id": 47, "unit": "Unit 1", "unitName": "Foundations of American Democracy", "concept": "Electoral College Origins", "question": "The Framers created the Electoral College because they:", "options": ["Trusted direct democracy fully", "Wanted to balance popular will with elite judgment", "Opposed any form of elections", "Believed only senators should choose the president"], "answer": "B", "explanation": "The Electoral College was a compromise between direct popular vote and congressional selection."},
    {"id": 48, "unit": "Unit 1", "unitName": "Foundations of American Democracy", "concept": "Elastic Clause Application", "question": "Congress used the Necessary and Proper Clause to justify creating:", "options": ["The National Park System only", "The Department of Defense only", "A national bank and many federal agencies", "State legislatures"], "answer": "C", "explanation": "The Elastic Clause has been used to create institutions like the national bank and federal agencies."},
    {"id": 49, "unit": "Unit 2", "unitName": "Interactions Among Branches", "concept": "Congressional Powers", "question": "Which is an expressed power of Congress?", "options": ["Establishing public schools", "Regulating local zoning", "Issuing driver's licenses", "Declaring war"], "answer": "D", "explanation": "The power to declare war is explicitly granted to Congress in Article I."},
    {"id": 50, "unit": "Unit 2", "unitName": "Interactions Among Branches", "concept": "Impeachment", "question": "The power to impeach a federal official belongs to:", "options": ["The Senate", "The Supreme Court", "The House of Representatives", "The president"], "answer": "C", "explanation": "The House has the sole power of impeachment; the Senate conducts the trial."},
    {"id": 51, "unit": "Unit 2", "unitName": "Interactions Among Branches", "concept": "Senate Confirmation", "question": "The Senate must confirm presidential appointments to:", "options": ["Federal courts and cabinet positions", "State legislatures", "Local school boards", "City councils"], "answer": "A", "explanation": "Advice and consent power gives the Senate a role in confirming federal judges and cabinet members."},
    {"id": 52, "unit": "Unit 2", "unitName": "Interactions Among Branches", "concept": "Filibuster", "question": "A filibuster in the Senate can be ended by:", "options": ["A cloture vote of 60 senators", "A simple majority vote", "A presidential order", "The Speaker of the House"], "answer": "A", "explanation": "Cloture requires 60 votes to end debate and force a vote on legislation."},
    {"id": 53, "unit": "Unit 2", "unitName": "Interactions Among Branches", "concept": "Speaker of the House", "question": "The Speaker of the House is significant because they:", "options": ["Are appointed by the president", "Serve as head of the judiciary", "Can override presidential vetoes alone", "Control the legislative agenda and floor proceedings"], "answer": "D", "explanation": "The Speaker controls which bills come to the floor and influences the legislative process."},
    {"id": 54, "unit": "Unit 2", "unitName": "Interactions Among Branches", "concept": "Committee System", "question": "Standing committees in Congress are important because they:", "options": ["Write the final version of all laws", "Have no real power", "Only deal with foreign policy", "Review and shape legislation before it reaches the full chamber"], "answer": "D", "explanation": "Standing committees specialize in policy areas and do the detailed work on legislation."},
    {"id": 55, "unit": "Unit 2", "unitName": "Interactions Among Branches", "concept": "Conference Committee", "question": "A conference committee is formed when:", "options": ["The president requests it", "The Supreme Court orders it", "The House and Senate pass different versions of the same bill", "A bill is vetoed"], "answer": "C", "explanation": "Conference committees reconcile differences between House and Senate versions of legislation."},
    {"id": 56, "unit": "Unit 2", "unitName": "Interactions Among Branches", "concept": "Presidential Veto", "question": "The president can check congressional power by:", "options": ["Dissolving Congress", "Appointing new members of Congress", "Changing the Constitution", "Vetoing legislation"], "answer": "D", "explanation": "The veto allows the president to reject bills, requiring a two-thirds override vote."},
    {"id": 57, "unit": "Unit 2", "unitName": "Interactions Among Branches", "concept": "Veto Override", "question": "Congress can override a presidential veto with:", "options": ["A simple majority in one chamber", "A two-thirds vote in both chambers", "A unanimous vote in the Senate", "Approval from the Supreme Court"], "answer": "B", "explanation": "A two-thirds supermajority in both the House and Senate overrides a veto."},
    {"id": 58, "unit": "Unit 2", "unitName": "Interactions Among Branches", "concept": "Executive Orders", "question": "Executive orders allow the president to:", "options": ["Create new laws without Congress", "Amend the Constitution", "Remove Supreme Court justices", "Direct federal agencies on policy implementation"], "answer": "D", "explanation": "Executive orders direct how executive agencies implement policy within existing law."},
    {"id": 59, "unit": "Unit 2", "unitName": "Interactions Among Branches", "concept": "War Powers Resolution", "question": "The War Powers Resolution of 1973 requires the president to:", "options": ["Notify Congress within 48 hours of deploying troops", "Seek congressional approval to declare war", "Get Supreme Court approval before military action", "Consult with the United Nations first"], "answer": "A", "explanation": "The president must notify Congress within 48 hours and withdraw troops within 60 days without authorization."},
    {"id": 60, "unit": "Unit 2", "unitName": "Interactions Among Branches", "concept": "Judicial Review", "question": "Judicial review gives the Supreme Court the power to:", "options": ["Write new legislation", "Override executive orders automatically", "Declare laws unconstitutional", "Appoint new judges"], "answer": "C", "explanation": "Judicial review allows courts to strike down laws that violate the Constitution."},
    {"id": 61, "unit": "Unit 2", "unitName": "Interactions Among Branches", "concept": "Stare Decisis", "question": "The principle of stare decisis means that courts should:", "options": ["Follow precedent established by earlier decisions", "Always side with the government", "Interpret the Constitution literally", "Defer to Congress on everything"], "answer": "A", "explanation": "Stare decisis promotes consistency by following previous judicial rulings."},
    {"id": 62, "unit": "Unit 2", "unitName": "Interactions Among Branches", "concept": "Appointment Power", "question": "The president nominates federal judges who must be confirmed by:", "options": ["The House of Representatives", "State governors", "The Senate", "A national referendum"], "answer": "C", "explanation": "The Senate provides advice and consent on judicial nominations."},
    {"id": 63, "unit": "Unit 2", "unitName": "Interactions Among Branches", "concept": "Bureaucratic Discretion", "question": "Bureaucratic discretion refers to the ability of agencies to:", "options": ["Ignore all laws", "Make judgments in implementing policy within guidelines Congress sets", "Override the president", "Amend the Constitution"], "answer": "B", "explanation": "Agencies use discretion to interpret and apply broadly written statutes."},
    {"id": 64, "unit": "Unit 2", "unitName": "Interactions Among Branches", "concept": "Iron Triangles", "question": "An iron triangle consists of:", "options": ["A congressional committee, an interest group, and a bureaucratic agency", "The president, vice president, and Speaker", "Three branches of government", "Three political parties"], "answer": "A", "explanation": "Iron triangles are mutually beneficial relationships among committees, agencies, and interest groups."},
    {"id": 65, "unit": "Unit 2", "unitName": "Interactions Among Branches", "concept": "Presidential Persuasion", "question": "Richard Neustadt argued that presidential power is primarily the power to:", "options": ["Persuade others to act", "Command the military", "Veto legislation", "Appoint judges"], "answer": "A", "explanation": "Neustadt emphasized that presidents succeed through bargaining and persuasion, not just formal authority."},
    {"id": 66, "unit": "Unit 2", "unitName": "Interactions Among Branches", "concept": "Bully Pulpit", "question": "The 'bully pulpit' refers to the president's ability to:", "options": ["Use the military to enforce laws", "Use the visibility of the office to shape public opinion", "Override Congress", "Appoint favorable judges"], "answer": "B", "explanation": "Presidents leverage media attention and public speaking to build support for their agenda."},
    {"id": 67, "unit": "Unit 2", "unitName": "Interactions Among Branches", "concept": "Signing Statements", "question": "Presidential signing statements are used to:", "options": ["Express the president's interpretation of a law when signing it", "Veto parts of a bill", "Override the Supreme Court", "Create new legislation"], "answer": "A", "explanation": "Presidents use signing statements to indicate how they intend to enforce or interpret legislation."},
    {"id": 68, "unit": "Unit 2", "unitName": "Interactions Among Branches", "concept": "Power of the Purse", "question": "Congress's 'power of the purse' means it controls:", "options": ["Federal spending and taxation", "Military operations", "Judicial appointments", "State budgets"], "answer": "A", "explanation": "Congress controls government spending through its authority over appropriations and revenue."},
    {"id": 69, "unit": "Unit 2", "unitName": "Interactions Among Branches", "concept": "Senate vs. House", "question": "Compared to the House, the Senate is considered more deliberative because:", "options": ["It has more members", "It only considers tax bills", "It has unlimited debate and the filibuster", "Members serve two-year terms"], "answer": "C", "explanation": "The Senate's rules allow extended debate, making it a more deliberative body."},
    {"id": 70, "unit": "Unit 2", "unitName": "Interactions Among Branches", "concept": "Logrolling", "question": "Logrolling in Congress refers to:", "options": ["Filibustering a bill", "Members exchanging votes to pass each other's legislation", "The president signing a bill into law", "Judicial review of legislation"], "answer": "B", "explanation": "Legislators trade votes on different bills to build coalitions of support."},
    {"id": 71, "unit": "Unit 2", "unitName": "Interactions Among Branches", "concept": "Discharge Petition", "question": "A discharge petition is used to:", "options": ["Impeach the president", "End a filibuster", "Force a bill out of committee for a floor vote", "Override a veto"], "answer": "C", "explanation": "If a majority of House members sign a discharge petition, a bill bypasses the committee."},
    {"id": 72, "unit": "Unit 2", "unitName": "Interactions Among Branches", "concept": "Pocket Veto", "question": "A pocket veto occurs when:", "options": ["The president does not sign a bill and Congress adjourns within 10 days", "The president signs a bill into law", "Congress overrides a veto", "The Supreme Court vetoes a law"], "answer": "A", "explanation": "If Congress adjourns before 10 days and the president hasn't signed, the bill dies."},
    {"id": 73, "unit": "Unit 2", "unitName": "Interactions Among Branches", "concept": "Judicial Activism", "question": "Judicial activism is the philosophy that courts should:", "options": ["Broadly interpret the Constitution to address social issues", "Only interpret law narrowly", "Defer to the legislature always", "Avoid ruling on any political questions"], "answer": "A", "explanation": "Activists believe courts should use their power to advance justice and protect rights."},
    {"id": 74, "unit": "Unit 2", "unitName": "Interactions Among Branches", "concept": "Judicial Restraint", "question": "Judicial restraint holds that judges should:", "options": ["Defer to elected branches and avoid overturning laws unless clearly unconstitutional", "Broadly interpret rights", "Always agree with the president", "Ignore precedent"], "answer": "A", "explanation": "Restraint advocates believe courts should not substitute their judgment for that of legislatures."},
    {"id": 75, "unit": "Unit 2", "unitName": "Interactions Among Branches", "concept": "Federalist No. 70", "question": "In Federalist No. 70, Alexander Hamilton argued for:", "options": ["A plural executive", "A weak presidency", "Eliminating the presidency", "An energetic, unitary executive"], "answer": "D", "explanation": "Hamilton believed a single, energetic executive was necessary for effective governance."},
    {"id": 76, "unit": "Unit 2", "unitName": "Interactions Among Branches", "concept": "Federalist No. 78", "question": "In Federalist No. 78, Hamilton described the judiciary as the:", "options": ["Least dangerous branch", "Most dangerous branch", "Most powerful branch", "Only necessary branch"], "answer": "A", "explanation": "Hamilton argued the judiciary has 'neither force nor will, but merely judgment.'"},
    {"id": 77, "unit": "Unit 2", "unitName": "Interactions Among Branches", "concept": "Executive Privilege", "question": "Executive privilege is the claim that the president:", "options": ["Is immune from all lawsuits", "Can fire any government employee", "Has the power to declare war", "Can withhold information from Congress and courts for national security"], "answer": "D", "explanation": "Presidents have claimed the right to keep certain communications confidential."},
    {"id": 78, "unit": "Unit 2", "unitName": "Interactions Among Branches", "concept": "Baker v. Carr", "question": "Baker v. Carr (1962) established the principle of:", "options": ["Executive privilege", "Freedom of the press", "'One person, one vote' and justiciability of redistricting", "Separation of church and state"], "answer": "C", "explanation": "The case established that redistricting issues are justiciable and subject to court review."},
    {"id": 79, "unit": "Unit 2", "unitName": "Interactions Among Branches", "concept": "Shaw v. Reno", "question": "Shaw v. Reno (1993) ruled that:", "options": ["Poll taxes are unconstitutional", "Racial gerrymandering is subject to strict scrutiny", "The filibuster is unconstitutional", "States cannot hold primaries"], "answer": "B", "explanation": "Bizarrely shaped districts drawn primarily by race violate the Equal Protection Clause."},
    {"id": 80, "unit": "Unit 2", "unitName": "Interactions Among Branches", "concept": "Trustee vs. Delegate", "question": "A member of Congress acting as a trustee:", "options": ["Votes only according to their constituents' wishes", "Follows the party leader always", "Abstains from voting", "Uses their own judgment to vote on legislation"], "answer": "D", "explanation": "Trustees exercise independent judgment rather than simply mirroring constituent opinion."},
    {"id": 81, "unit": "Unit 2", "unitName": "Interactions Among Branches", "concept": "Delegate Model", "question": "Under the delegate model of representation, a legislator should:", "options": ["Vote based on personal beliefs", "Follow the president's directives", "Ignore public opinion", "Vote according to the wishes of their constituents"], "answer": "D", "explanation": "Delegates act as mouthpieces for the people who elected them."},
    {"id": 82, "unit": "Unit 2", "unitName": "Interactions Among Branches", "concept": "Politico Model", "question": "The politico model of representation combines aspects of:", "options": ["Only the trustee model", "Only the delegate model", "Both trustee and delegate models depending on the issue", "Neither model"], "answer": "C", "explanation": "Politicos balance personal judgment and constituent preferences depending on the situation."},
    {"id": 83, "unit": "Unit 2", "unitName": "Interactions Among Branches", "concept": "Divided Government", "question": "Divided government occurs when:", "options": ["One party controls both Congress and the presidency", "The Supreme Court disagrees with Congress", "Different parties control the presidency and at least one chamber of Congress", "States conflict with federal law"], "answer": "C", "explanation": "Divided government often leads to gridlock as competing parties struggle to pass legislation."},
    {"id": 84, "unit": "Unit 2", "unitName": "Interactions Among Branches", "concept": "Bureaucratic Rule-Making", "question": "Federal agencies create regulations through a process called:", "options": ["Adjudication", "Filibustering", "Rule-making", "Gerrymandering"], "answer": "C", "explanation": "Rule-making allows agencies to establish detailed rules that have the force of law."},
    {"id": 85, "unit": "Unit 2", "unitName": "Interactions Among Branches", "concept": "Independent Regulatory Commissions", "question": "Independent regulatory commissions differ from cabinet departments because they:", "options": ["Operate with more independence from presidential control", "Report directly to the president", "Have no authority", "Are part of Congress"], "answer": "A", "explanation": "Independent commissions like the FCC are designed to be insulated from direct presidential influence."},
    {"id": 86, "unit": "Unit 2", "unitName": "Interactions Among Branches", "concept": "Government Corporations", "question": "An example of a government corporation is:", "options": ["The Department of State", "The United States Postal Service", "The FBI", "The National Guard"], "answer": "B", "explanation": "Government corporations like USPS provide services that could be offered by the private sector."},
    {"id": 87, "unit": "Unit 2", "unitName": "Interactions Among Branches", "concept": "Congressional Oversight", "question": "Congressional oversight of the bureaucracy includes:", "options": ["Appointing agency heads", "Holding hearings and controlling agency budgets", "Issuing executive orders", "Filing lawsuits"], "answer": "B", "explanation": "Congress uses hearings, investigations, and budget control to oversee executive agencies."},
    {"id": 88, "unit": "Unit 2", "unitName": "Interactions Among Branches", "concept": "22nd Amendment", "question": "The 22nd Amendment limits the president to:", "options": ["One term", "Two terms", "Three terms", "No term limits"], "answer": "B", "explanation": "Ratified in 1951, the amendment limits presidents to two four-year terms."},
    {"id": 89, "unit": "Unit 2", "unitName": "Interactions Among Branches", "concept": "25th Amendment", "question": "The 25th Amendment addresses:", "options": ["Congressional term limits", "Voting age", "Presidential succession and disability", "Income tax"], "answer": "C", "explanation": "The amendment outlines procedures when a president is unable to serve."},
    {"id": 90, "unit": "Unit 2", "unitName": "Interactions Among Branches", "concept": "Gerrymandering", "question": "Gerrymandering refers to the practice of:", "options": ["Lobbying Congress", "Filibustering in the Senate", "Drawing district lines to favor a political party", "Presidential vetoing"], "answer": "C", "explanation": "Gerrymandering manipulates district boundaries for political advantage."},
    {"id": 91, "unit": "Unit 2", "unitName": "Interactions Among Branches", "concept": "Pork Barrel Spending", "question": "Pork barrel spending refers to:", "options": ["Defense spending only", "Government funding directed to a representative's district to win constituent support", "Foreign aid", "Judicial salaries"], "answer": "B", "explanation": "Members of Congress secure funding for local projects to gain electoral support."},
    {"id": 92, "unit": "Unit 2", "unitName": "Interactions Among Branches", "concept": "Incumbency Advantage", "question": "Incumbents in Congress have an advantage because of:", "options": ["Name recognition, franking privileges, and easier fundraising", "Term limits", "Judicial support", "Mandatory re-election"], "answer": "A", "explanation": "Incumbents benefit from visibility, constituent services, and access to donors."},
    {"id": 93, "unit": "Unit 2", "unitName": "Interactions Among Branches", "concept": "Legislation Process (Stimulus)", "question": "A bill has been passed by both the House and Senate in different forms. What must happen next?", "options": ["The president signs both versions", "The Supreme Court chooses the better version", "A conference committee reconciles the two versions", "The bill dies automatically"], "answer": "C", "explanation": "A conference committee resolves differences before sending a unified bill for final passage."},
    {"id": 94, "unit": "Unit 2", "unitName": "Interactions Among Branches", "concept": "Cabinet Departments", "question": "The president's cabinet serves primarily to:", "options": ["Write legislation", "Confirm judicial appointments", "Override vetoes", "Advise the president and lead executive departments"], "answer": "D", "explanation": "Cabinet members head departments and advise the president on policy."},
    {"id": 95, "unit": "Unit 2", "unitName": "Interactions Among Branches", "concept": "Informal Presidential Powers", "question": "Which is considered an informal power of the president?", "options": ["Vetoing a bill", "Nominating judges", "Negotiating executive agreements with foreign leaders", "Serving as commander in chief"], "answer": "C", "explanation": "Executive agreements don't require Senate approval and are an informal expansion of presidential power."},
    {"id": 96, "unit": "Unit 3", "unitName": "Civil Liberties and Civil Rights", "concept": "First Amendment", "question": "The First Amendment protects all of the following EXCEPT:", "options": ["Freedom of speech", "Freedom of religion", "Freedom of the press", "Right to bear arms"], "answer": "D", "explanation": "The Second Amendment, not the First, protects the right to bear arms."},
    {"id": 97, "unit": "Unit 3", "unitName": "Civil Liberties and Civil Rights", "concept": "Establishment Clause", "question": "The Establishment Clause prohibits the government from:", "options": ["Establishing an official religion", "Allowing religious practice", "Taxing churches", "Censoring religious speech"], "answer": "A", "explanation": "The Establishment Clause creates a separation between government and religion."},
    {"id": 98, "unit": "Unit 3", "unitName": "Civil Liberties and Civil Rights", "concept": "Free Exercise Clause", "question": "The Free Exercise Clause protects individuals' right to:", "options": ["Avoid paying taxes", "Ignore criminal laws for religious reasons", "Receive government funding for worship", "Practice any religion without government interference"], "answer": "D", "explanation": "The government generally cannot prohibit religious practice, though neutral laws of general applicability may apply."},
    {"id": 99, "unit": "Unit 3", "unitName": "Civil Liberties and Civil Rights", "concept": "Engel v. Vitale", "question": "In Engel v. Vitale (1962), the Supreme Court ruled that:", "options": ["Students can pray in school", "Religious clubs cannot meet in public schools", "School-sponsored prayer violates the Establishment Clause", "Teachers must teach creationism"], "answer": "C", "explanation": "The Court struck down state-composed prayers in public schools."},
    {"id": 100, "unit": "Unit 3", "unitName": "Civil Liberties and Civil Rights", "concept": "Lemon v. Kurtzman", "question": "The Lemon test from Lemon v. Kurtzman requires that a law:", "options": ["Must promote religion", "Must benefit all religions equally", "Can favor one religion over another", "Have a secular purpose, not advance or inhibit religion, and avoid excessive entanglement"], "answer": "D", "explanation": "The three-pronged Lemon test guides Establishment Clause cases."},
    {"id": 101, "unit": "Unit 3", "unitName": "Civil Liberties and Civil Rights", "concept": "Tinker v. Des Moines", "question": "In Tinker v. Des Moines (1969), the Court ruled that students:", "options": ["Have no rights in school", "Can say anything without consequence", "Do not shed their constitutional rights at the schoolhouse gate", "Must follow all school dress codes"], "answer": "C", "explanation": "The Court protected student symbolic speech (black armbands) that didn't disrupt school."},
    {"id": 102, "unit": "Unit 3", "unitName": "Civil Liberties and Civil Rights", "concept": "Schenck v. United States", "question": "Schenck v. United States (1919) established the:", "options": ["Right to unlimited speech", "Right to protest during wartime", "Clear and present danger test for limiting speech", "Freedom from censorship"], "answer": "C", "explanation": "Justice Holmes argued speech creating a 'clear and present danger' can be restricted."},
    {"id": 103, "unit": "Unit 3", "unitName": "Civil Liberties and Civil Rights", "concept": "New York Times v. Sullivan", "question": "New York Times v. Sullivan (1964) made it harder for public officials to win libel suits by requiring proof of:", "options": ["Any false statement", "Actual malice — knowledge that a statement was false or reckless disregard for truth", "Intent to harm", "Financial damage only"], "answer": "B", "explanation": "The 'actual malice' standard protects press criticism of public officials."},
    {"id": 104, "unit": "Unit 3", "unitName": "Civil Liberties and Civil Rights", "concept": "Prior Restraint", "question": "Prior restraint refers to:", "options": ["Punishing speech after it occurs", "Government censorship that prevents speech before publication", "Regulating commercial speech", "Limiting campaign contributions"], "answer": "B", "explanation": "The Court has generally held that prior restraint is presumptively unconstitutional."},
    {"id": 105, "unit": "Unit 3", "unitName": "Civil Liberties and Civil Rights", "concept": "Second Amendment", "question": "The Second Amendment protects:", "options": ["Freedom of the press", "The right to keep and bear arms", "Freedom of religion", "The right to a fair trial"], "answer": "B", "explanation": "The Second Amendment has been interpreted to protect an individual's right to own firearms."},
    {"id": 106, "unit": "Unit 3", "unitName": "Civil Liberties and Civil Rights", "concept": "McDonald v. Chicago", "question": "McDonald v. Chicago (2010) incorporated the Second Amendment by ruling that:", "options": ["The federal government can ban all guns", "Only the military can own weapons", "Gun regulations are always unconstitutional", "States and cities cannot completely ban handgun ownership"], "answer": "D", "explanation": "The Court applied the Second Amendment to state and local governments through incorporation."},
    {"id": 107, "unit": "Unit 3", "unitName": "Civil Liberties and Civil Rights", "concept": "Fourth Amendment", "question": "The Fourth Amendment protects against:", "options": ["Self-incrimination", "Cruel punishment", "Double jeopardy", "Unreasonable searches and seizures"], "answer": "D", "explanation": "The Fourth Amendment requires probable cause and often warrants for searches."},
    {"id": 108, "unit": "Unit 3", "unitName": "Civil Liberties and Civil Rights", "concept": "Exclusionary Rule", "question": "The exclusionary rule means that:", "options": ["All evidence is admissible", "Evidence obtained illegally cannot be used in court", "Defendants cannot testify", "Judges can exclude witnesses"], "answer": "B", "explanation": "Mapp v. Ohio (1961) applied the exclusionary rule to state courts."},
    {"id": 109, "unit": "Unit 3", "unitName": "Civil Liberties and Civil Rights", "concept": "Fifth Amendment", "question": "The Fifth Amendment protects individuals from:", "options": ["Unreasonable searches", "Self-incrimination and double jeopardy", "Cruel punishment", "Excessive bail"], "answer": "B", "explanation": "The Fifth Amendment includes the right to remain silent and protection from being tried twice."},
    {"id": 110, "unit": "Unit 3", "unitName": "Civil Liberties and Civil Rights", "concept": "Miranda v. Arizona", "question": "Miranda v. Arizona (1966) requires police to:", "options": ["Obtain a search warrant before any arrest", "Inform suspects of their rights before custodial interrogation", "Allow suspects to leave at any time", "Provide an attorney at the scene"], "answer": "B", "explanation": "The Miranda warning ensures suspects know their Fifth and Sixth Amendment rights."},
    {"id": 111, "unit": "Unit 3", "unitName": "Civil Liberties and Civil Rights", "concept": "Sixth Amendment", "question": "The Sixth Amendment guarantees the right to:", "options": ["Bear arms", "Be free from excessive bail", "A speedy and public trial with an attorney", "Privacy"], "answer": "C", "explanation": "The Sixth Amendment ensures a speedy trial, an impartial jury, and the right to counsel."},
    {"id": 112, "unit": "Unit 3", "unitName": "Civil Liberties and Civil Rights", "concept": "Gideon v. Wainwright", "question": "Gideon v. Wainwright (1963) established that:", "options": ["States must provide attorneys for defendants who cannot afford one", "The death penalty is cruel and unusual", "Police must read Miranda rights", "All trials must have a jury"], "answer": "A", "explanation": "The Court ruled the Sixth Amendment right to counsel applies to state courts."},
    {"id": 113, "unit": "Unit 3", "unitName": "Civil Liberties and Civil Rights", "concept": "Eighth Amendment", "question": "The Eighth Amendment prohibits:", "options": ["Unreasonable searches", "Excessive bail, fines, and cruel and unusual punishment", "Self-incrimination", "Quartering of soldiers"], "answer": "B", "explanation": "The Eighth Amendment limits the government's power to punish."},
    {"id": 114, "unit": "Unit 3", "unitName": "Civil Liberties and Civil Rights", "concept": "Right to Privacy", "question": "The right to privacy is:", "options": ["Explicitly stated in the First Amendment", "Guaranteed by the Tenth Amendment only", "Not explicitly in the Constitution but inferred from several amendments", "Stated in Article III"], "answer": "C", "explanation": "The Court has found a right to privacy in the penumbras of the 1st, 3rd, 4th, 5th, and 9th Amendments."},
    {"id": 115, "unit": "Unit 3", "unitName": "Civil Liberties and Civil Rights", "concept": "Roe v. Wade", "question": "Roe v. Wade (1973) ruled that the right to privacy:", "options": ["Includes a woman's decision to have an abortion, subject to state interests", "Does not exist", "Is absolute", "Only applies to medical records"], "answer": "A", "explanation": "The Court established a trimester framework balancing women's rights and state interests."},
    {"id": 116, "unit": "Unit 3", "unitName": "Civil Liberties and Civil Rights", "concept": "14th Amendment Equal Protection", "question": "The Equal Protection Clause of the 14th Amendment requires that:", "options": ["The federal government cannot tax citizens", "States treat all persons within their jurisdiction equally under the law", "Only citizens have rights", "States can discriminate based on religion"], "answer": "B", "explanation": "Equal protection has been the basis for challenging racial, gender, and other discrimination."},
    {"id": 117, "unit": "Unit 3", "unitName": "Civil Liberties and Civil Rights", "concept": "Brown v. Board of Education", "question": "Brown v. Board of Education (1954) overturned the 'separate but equal' doctrine by ruling that:", "options": ["Separate educational facilities are inherently unequal", "Schools could remain segregated", "Only private schools could segregate", "Integration was optional"], "answer": "A", "explanation": "The unanimous decision declared racial segregation in public schools unconstitutional."},
    {"id": 118, "unit": "Unit 3", "unitName": "Civil Liberties and Civil Rights", "concept": "Civil Rights Act of 1964", "question": "The Civil Rights Act of 1964 prohibited discrimination based on:", "options": ["Only race", "Only gender", "Race, color, religion, sex, and national origin", "Age and disability only"], "answer": "C", "explanation": "The landmark legislation banned discrimination in employment, public accommodations, and federally funded programs."},
    {"id": 119, "unit": "Unit 3", "unitName": "Civil Liberties and Civil Rights", "concept": "Voting Rights Act of 1965", "question": "The Voting Rights Act of 1965 was primarily aimed at:", "options": ["Lowering the voting age", "Establishing the Electoral College", "Allowing felons to vote", "Eliminating barriers that prevented African Americans from voting"], "answer": "D", "explanation": "The Act banned literacy tests and authorized federal oversight of elections in discriminatory areas."},
    {"id": 120, "unit": "Unit 3", "unitName": "Civil Liberties and Civil Rights", "concept": "Letter from Birmingham Jail (Stimulus)", "question": "\"One who breaks an unjust law must do so openly, lovingly, and with a willingness to accept the penalty.\" — Martin Luther King Jr.\n\nKing is advocating for:", "options": ["Civil disobedience with acceptance of consequences", "Violent revolution", "Ignoring all laws", "Working only through the courts"], "answer": "A", "explanation": "King defended nonviolent civil disobedience as a moral duty."},
    {"id": 121, "unit": "Unit 3", "unitName": "Civil Liberties and Civil Rights", "concept": "Strict Scrutiny", "question": "Under strict scrutiny, the government must show that a law:", "options": ["Is narrowly tailored to serve a compelling government interest", "Has any rational basis", "Benefits the majority", "Was passed by a supermajority"], "answer": "A", "explanation": "Strict scrutiny is the highest standard of review, applied to racial classifications and fundamental rights."},
    {"id": 122, "unit": "Unit 3", "unitName": "Civil Liberties and Civil Rights", "concept": "Intermediate Scrutiny", "question": "Intermediate scrutiny is typically applied in cases involving:", "options": ["Race", "National origin", "Fundamental rights", "Gender"], "answer": "D", "explanation": "Gender-based classifications are reviewed under intermediate scrutiny."},
    {"id": 123, "unit": "Unit 3", "unitName": "Civil Liberties and Civil Rights", "concept": "Rational Basis Review", "question": "Under rational basis review, a law is upheld if it:", "options": ["Serves a compelling interest", "Is rationally related to a legitimate government interest", "Is narrowly tailored", "Treats everyone identically"], "answer": "B", "explanation": "Rational basis is the most deferential standard and applies to most economic and social legislation."},
    {"id": 124, "unit": "Unit 3", "unitName": "Civil Liberties and Civil Rights", "concept": "Affirmative Action", "question": "In Grutter v. Bollinger (2003), the Supreme Court ruled that:", "options": ["Race can never be considered in admissions", "Race can be one factor in a holistic admissions process to achieve diversity", "Quotas are acceptable", "Affirmative action is always unconstitutional"], "answer": "B", "explanation": "The Court upheld the use of race as one factor in university admissions."},
    {"id": 125, "unit": "Unit 3", "unitName": "Civil Liberties and Civil Rights", "concept": "Title IX", "question": "Title IX of the Education Amendments of 1972 prohibits:", "options": ["Racial discrimination in voting", "Gender discrimination in federally funded education programs", "Age discrimination in employment", "Disability discrimination in housing"], "answer": "B", "explanation": "Title IX ensures equal access to educational opportunities regardless of gender."},
    {"id": 126, "unit": "Unit 3", "unitName": "Civil Liberties and Civil Rights", "concept": "Due Process", "question": "Procedural due process requires that the government:", "options": ["Never enforce any law", "Follow fair procedures before depriving someone of life, liberty, or property", "Allow everyone to vote in all elections", "Provide free education to all"], "answer": "B", "explanation": "The 5th and 14th Amendments require fair legal proceedings."},
    {"id": 127, "unit": "Unit 3", "unitName": "Civil Liberties and Civil Rights", "concept": "Substantive Due Process", "question": "Substantive due process protects individuals from:", "options": ["Only procedural errors", "Criminal prosecution", "All forms of taxation", "Government actions that are arbitrary regardless of procedures followed"], "answer": "D", "explanation": "Substantive due process limits what the government can do, not just how it does it."},
    {"id": 128, "unit": "Unit 3", "unitName": "Civil Liberties and Civil Rights", "concept": "Wisconsin v. Yoder", "question": "In Wisconsin v. Yoder (1972), the Court ruled that:", "options": ["All children must attend public school", "Religious exemptions never apply to education", "Amish families could withdraw children from school after 8th grade on religious grounds", "Home schooling is unconstitutional"], "answer": "C", "explanation": "The Free Exercise Clause protected the Amish practice of ending formal education early."},
    {"id": 129, "unit": "Unit 3", "unitName": "Civil Liberties and Civil Rights", "concept": "Symbolic Speech", "question": "Which Supreme Court case protected symbolic speech in the form of flag burning?", "options": ["Texas v. Johnson", "Schenck v. United States", "Tinker v. Des Moines", "Brandenburg v. Ohio"], "answer": "A", "explanation": "Texas v. Johnson (1989) ruled flag burning is protected expression under the First Amendment."},
    {"id": 130, "unit": "Unit 3", "unitName": "Civil Liberties and Civil Rights", "concept": "Hate Speech", "question": "Under current First Amendment jurisprudence, hate speech is:", "options": ["Generally protected unless it incites imminent lawless action", "Never protected", "Always a criminal offense", "Regulated by the FCC"], "answer": "A", "explanation": "The Brandenburg test protects even offensive speech unless it directly incites imminent violence."},
    {"id": 131, "unit": "Unit 3", "unitName": "Civil Liberties and Civil Rights", "concept": "15th Amendment", "question": "The 15th Amendment prohibits denying the right to vote based on:", "options": ["Gender", "Age", "Race, color, or previous condition of servitude", "Property ownership"], "answer": "C", "explanation": "Ratified in 1870, the 15th Amendment extended voting rights to African American men."},
    {"id": 132, "unit": "Unit 3", "unitName": "Civil Liberties and Civil Rights", "concept": "19th Amendment", "question": "The 19th Amendment granted:", "options": ["Freedom of speech to all", "Abolition of slavery", "Voting rights to women", "Equal protection under law"], "answer": "C", "explanation": "Ratified in 1920, the 19th Amendment prohibited denying the vote based on sex."},
    {"id": 133, "unit": "Unit 3", "unitName": "Civil Liberties and Civil Rights", "concept": "24th Amendment", "question": "The 24th Amendment eliminated:", "options": ["The Electoral College", "Literacy tests", "Poll taxes in federal elections", "The filibuster"], "answer": "C", "explanation": "Poll taxes had been used to disenfranchise poor and minority voters."},
    {"id": 134, "unit": "Unit 3", "unitName": "Civil Liberties and Civil Rights", "concept": "Selective Incorporation Detail", "question": "Which case incorporated the right to counsel to the states?", "options": ["Gideon v. Wainwright", "Mapp v. Ohio", "Miranda v. Arizona", "Roe v. Wade"], "answer": "A", "explanation": "Gideon v. Wainwright (1963) applied the Sixth Amendment right to counsel to state courts."},
    {"id": 135, "unit": "Unit 3", "unitName": "Civil Liberties and Civil Rights", "concept": "Mapp v. Ohio", "question": "Mapp v. Ohio (1961) applied the exclusionary rule to the states, meaning:", "options": ["All evidence is always admissible in state courts", "States can create their own search rules", "Only federal courts follow the Fourth Amendment", "Illegally obtained evidence cannot be used in state criminal trials"], "answer": "D", "explanation": "The ruling extended the Fourth Amendment protection against illegal searches to state proceedings."},
    {"id": 136, "unit": "Unit 3", "unitName": "Civil Liberties and Civil Rights", "concept": "Citizens United v. FEC", "question": "Citizens United v. FEC (2010) ruled that:", "options": ["Political spending by corporations is protected under the First Amendment", "Corporations cannot participate in politics", "Campaign contributions have no limits", "Only individuals can donate to campaigns"], "answer": "A", "explanation": "The Court held that restricting independent political expenditures by corporations violates free speech."},
    {"id": 137, "unit": "Unit 3", "unitName": "Civil Liberties and Civil Rights", "concept": "Cruel and Unusual Punishment", "question": "Which case addressed whether the death penalty constitutes cruel and unusual punishment?", "options": ["Gideon v. Wainwright", "Furman v. Georgia", "Miranda v. Arizona", "Mapp v. Ohio"], "answer": "B", "explanation": "Furman v. Georgia (1972) imposed a moratorium on the death penalty as then applied."},
    {"id": 138, "unit": "Unit 3", "unitName": "Civil Liberties and Civil Rights", "concept": "13th Amendment", "question": "The 13th Amendment:", "options": ["Granted citizenship to all born in the U.S.", "Guaranteed equal protection", "Abolished slavery and involuntary servitude", "Extended voting rights to African Americans"], "answer": "C", "explanation": "Ratified in 1865, the 13th Amendment ended slavery in the United States."},
    {"id": 139, "unit": "Unit 3", "unitName": "Civil Liberties and Civil Rights", "concept": "De Facto vs. De Jure Segregation", "question": "De facto segregation differs from de jure segregation because it:", "options": ["Is required by law", "Only occurs in the South", "Was ended by Brown v. Board", "Exists in practice without legal mandate"], "answer": "D", "explanation": "De facto segregation arises from social and economic conditions rather than legislation."},
    {"id": 140, "unit": "Unit 3", "unitName": "Civil Liberties and Civil Rights", "concept": "Plessy v. Ferguson", "question": "Plessy v. Ferguson (1896) established the doctrine of:", "options": ["Judicial review", "Selective incorporation", "Strict scrutiny", "Separate but equal"], "answer": "D", "explanation": "The 'separate but equal' doctrine allowed legally mandated racial segregation until Brown overturned it."},
    {"id": 141, "unit": "Unit 4", "unitName": "American Political Ideologies and Beliefs", "concept": "Liberal vs. Conservative", "question": "On economic issues, liberals generally favor:", "options": ["Lower taxes and less regulation", "Eliminating all government programs", "Privatizing Social Security", "Government regulation and social welfare programs"], "answer": "D", "explanation": "Liberals typically support government intervention to reduce inequality."},
    {"id": 142, "unit": "Unit 4", "unitName": "American Political Ideologies and Beliefs", "concept": "Conservative Economic Views", "question": "Conservatives typically support:", "options": ["Higher taxes on the wealthy", "Free-market principles and limited government regulation", "Expanding government programs", "Nationalizing industries"], "answer": "B", "explanation": "Conservatives generally favor a smaller role for government in the economy."},
    {"id": 143, "unit": "Unit 4", "unitName": "American Political Ideologies and Beliefs", "concept": "Libertarian Ideology", "question": "Libertarians generally believe in:", "options": ["Strong government regulation", "Extensive social welfare", "Minimal government intervention in both economic and social affairs", "Government control of the economy"], "answer": "C", "explanation": "Libertarians advocate for individual freedom and limited government in all areas."},
    {"id": 144, "unit": "Unit 4", "unitName": "American Political Ideologies and Beliefs", "concept": "Political Socialization", "question": "The most important agent of political socialization is typically:", "options": ["The media", "Schools", "Peer groups", "The family"], "answer": "D", "explanation": "Family is usually the strongest early influence on political attitudes and party identification."},
    {"id": 145, "unit": "Unit 4", "unitName": "American Political Ideologies and Beliefs", "concept": "Media Influence", "question": "The media's role in political socialization includes:", "options": ["Having no influence on public opinion", "Shaping the public agenda through coverage choices", "Directly controlling how people vote", "Replacing family as the primary influence"], "answer": "B", "explanation": "Media helps set the political agenda by deciding what issues receive coverage."},
    {"id": 146, "unit": "Unit 4", "unitName": "American Political Ideologies and Beliefs", "concept": "Public Opinion Polls", "question": "A scientific public opinion poll requires:", "options": ["A random sample representative of the population", "Asking only people who volunteer", "Surveying only political experts", "Asking leading questions"], "answer": "A", "explanation": "Random sampling ensures the poll accurately represents the broader population."},
    {"id": 147, "unit": "Unit 4", "unitName": "American Political Ideologies and Beliefs", "concept": "Sampling Error", "question": "The margin of error in a poll reflects:", "options": ["How biased the questions are", "How many people refused to answer", "The range within which the true value likely falls", "The cost of conducting the poll"], "answer": "C", "explanation": "Margin of error indicates the statistical uncertainty in poll results."},
    {"id": 148, "unit": "Unit 4", "unitName": "American Political Ideologies and Beliefs", "concept": "Ideology Spectrum", "question": "On the political spectrum, someone who favors tradition, lower taxes, and a strong military is likely:", "options": ["Conservative", "Liberal", "Libertarian", "Socialist"], "answer": "A", "explanation": "These positions align with mainstream conservative ideology."},
    {"id": 149, "unit": "Unit 4", "unitName": "American Political Ideologies and Beliefs", "concept": "Gender Gap", "question": "The 'gender gap' in American politics refers to:", "options": ["Men and women voting at different rates", "Differences in political opinions and voting patterns between men and women", "Women being unable to run for office", "Equal representation in Congress"], "answer": "B", "explanation": "Women tend to lean more Democratic, while men tend to lean more Republican."},
    {"id": 150, "unit": "Unit 4", "unitName": "American Political Ideologies and Beliefs", "concept": "Generational Effects", "question": "Political events experienced during young adulthood can shape a generation's political views. This is called:", "options": ["Political apathy", "Random socialization", "Generational effect", "Ideological purity"], "answer": "C", "explanation": "Major events like wars, recessions, or movements can define a generation's politics."},
    {"id": 151, "unit": "Unit 4", "unitName": "American Political Ideologies and Beliefs", "concept": "Entitlement Programs", "question": "Social Security and Medicare are called entitlement programs because:", "options": ["Eligible individuals are legally entitled to benefits", "Only certain people qualify based on need", "They require annual congressional approval", "They are funded by state governments"], "answer": "A", "explanation": "Entitlements guarantee benefits to all who meet eligibility criteria."},
    {"id": 152, "unit": "Unit 4", "unitName": "American Political Ideologies and Beliefs", "concept": "Federal Budget", "question": "The largest portion of mandatory federal spending goes to:", "options": ["Defense", "Social Security and Medicare", "Education", "Foreign aid"], "answer": "B", "explanation": "Entitlement programs like Social Security and Medicare dominate mandatory spending."},
    {"id": 153, "unit": "Unit 4", "unitName": "American Political Ideologies and Beliefs", "concept": "Deficit vs. Debt", "question": "The national debt differs from the annual deficit because the debt:", "options": ["Is the total accumulation of all past deficits", "Is always decreasing", "Only includes foreign borrowing", "Is the same as the deficit"], "answer": "A", "explanation": "The national debt is the cumulative total of all annual budget deficits over time."},
    {"id": 154, "unit": "Unit 4", "unitName": "American Political Ideologies and Beliefs", "concept": "Supply-Side Economics", "question": "Supply-side economics argues that economic growth is best achieved by:", "options": ["Raising taxes on corporations", "Lowering taxes to stimulate investment and production", "Increasing government spending on social programs", "Imposing trade tariffs"], "answer": "B", "explanation": "Supply-siders believe tax cuts incentivize investment and economic growth."},
    {"id": 155, "unit": "Unit 4", "unitName": "American Political Ideologies and Beliefs", "concept": "Keynesian Economics", "question": "Keynesian economics advocates that during a recession, the government should:", "options": ["Cut spending dramatically", "Increase spending to stimulate demand", "Do nothing", "Raise interest rates"], "answer": "B", "explanation": "Keynes argued government spending can compensate for reduced private demand."},
    {"id": 156, "unit": "Unit 4", "unitName": "American Political Ideologies and Beliefs", "concept": "Social Policy Views", "question": "On social issues like same-sex marriage, conservatives tend to:", "options": ["Support expanded rights", "Oppose changes to traditional definitions", "Have no opinion", "Favor government mandates"], "answer": "B", "explanation": "Social conservatives typically support traditional values and institutions."},
    {"id": 157, "unit": "Unit 4", "unitName": "American Political Ideologies and Beliefs", "concept": "Education Policy", "question": "Conservatives generally favor education policies that include:", "options": ["Increased federal control", "School choice through vouchers and charter schools", "Eliminating private schools", "Mandatory national curriculum"], "answer": "B", "explanation": "Conservatives often support market-based approaches to education."},
    {"id": 158, "unit": "Unit 4", "unitName": "American Political Ideologies and Beliefs", "concept": "Environmental Policy", "question": "Liberals generally support environmental regulations because they believe:", "options": ["The free market will solve environmental problems", "Government action is necessary to protect public health and the environment", "Environmental issues are not important", "Only state governments should regulate"], "answer": "B", "explanation": "Liberals typically favor federal environmental regulations and climate action."},
    {"id": 159, "unit": "Unit 4", "unitName": "American Political Ideologies and Beliefs", "concept": "Immigration Views", "question": "A political candidate who supports a path to citizenship for undocumented immigrants likely holds:", "options": ["Liberal views on immigration", "Conservative views on immigration", "Libertarian economic views", "Populist views"], "answer": "A", "explanation": "Support for a path to citizenship is associated with liberal immigration policy."},
    {"id": 160, "unit": "Unit 4", "unitName": "American Political Ideologies and Beliefs", "concept": "Healthcare Policy", "question": "Which statement best reflects a liberal view on healthcare?", "options": ["The government should provide universal healthcare coverage", "Healthcare should be entirely privatized", "The government should not be involved in healthcare", "Only the wealthy should have access to healthcare"], "answer": "A", "explanation": "Liberals generally support expanding government's role in providing healthcare."},
    {"id": 161, "unit": "Unit 4", "unitName": "American Political Ideologies and Beliefs", "concept": "Gun Control", "question": "Liberals are more likely than conservatives to support:", "options": ["Expanded gun rights", "Eliminating all gun laws", "Stricter gun control legislation", "Arming teachers"], "answer": "C", "explanation": "Liberals tend to favor gun safety regulations and restrictions."},
    {"id": 162, "unit": "Unit 4", "unitName": "American Political Ideologies and Beliefs", "concept": "Criminal Justice Reform", "question": "Liberals are more likely to advocate for:", "options": ["Mandatory minimum sentences", "Expanding the death penalty", "Reforming the criminal justice system to reduce mass incarceration", "Increasing police funding without oversight"], "answer": "C", "explanation": "Liberals often emphasize rehabilitation and addressing systemic inequities in criminal justice."},
    {"id": 163, "unit": "Unit 4", "unitName": "American Political Ideologies and Beliefs", "concept": "Fiscal Policy", "question": "Fiscal policy involves the government using:", "options": ["Taxation and spending to influence the economy", "Interest rates to control inflation", "Military force", "Judicial appointments"], "answer": "A", "explanation": "Fiscal policy uses government revenue and expenditure as tools to manage economic conditions."},
    {"id": 164, "unit": "Unit 4", "unitName": "American Political Ideologies and Beliefs", "concept": "Monetary Policy", "question": "Monetary policy is primarily managed by:", "options": ["Congress", "The president", "The Federal Reserve", "State governments"], "answer": "C", "explanation": "The Federal Reserve controls the money supply and interest rates."},
    {"id": 165, "unit": "Unit 4", "unitName": "American Political Ideologies and Beliefs", "concept": "Trade Policy", "question": "Free trade agreements are generally supported by those who believe:", "options": ["Open markets benefit consumers through lower prices and more choices", "All trade should be banned", "Tariffs protect domestic jobs", "Only exports matter"], "answer": "A", "explanation": "Free trade advocates argue that reducing barriers benefits economies overall."},
    {"id": 166, "unit": "Unit 4", "unitName": "American Political Ideologies and Beliefs", "concept": "Welfare Policy", "question": "TANF (Temporary Assistance for Needy Families) differs from earlier welfare because it:", "options": ["Includes work requirements and time limits", "Has no time limits", "Is available to everyone", "Provides unlimited benefits"], "answer": "A", "explanation": "The 1996 welfare reform imposed work requirements and five-year limits."},
    {"id": 167, "unit": "Unit 4", "unitName": "American Political Ideologies and Beliefs", "concept": "Populism", "question": "Populism as a political ideology emphasizes:", "options": ["Elite rule", "The concerns and power of ordinary people against the elite", "Judicial supremacy", "Corporate interests"], "answer": "B", "explanation": "Populists position themselves as champions of the common people against powerful elites."},
    {"id": 168, "unit": "Unit 4", "unitName": "American Political Ideologies and Beliefs", "concept": "Neoconservatism", "question": "Neoconservatives are most associated with support for:", "options": ["Isolationist foreign policy", "Reducing defense spending", "Pacifism", "Promoting democracy abroad through an active foreign policy including military force"], "answer": "D", "explanation": "Neoconservatives advocate for an assertive U.S. role in international affairs."},
    {"id": 169, "unit": "Unit 4", "unitName": "American Political Ideologies and Beliefs", "concept": "Push Polls", "question": "Push polls are problematic because they:", "options": ["Use random sampling", "Ask neutral questions", "Have large sample sizes", "Use leading questions designed to influence respondents' opinions rather than measure them"], "answer": "D", "explanation": "Push polls are a form of propaganda disguised as polling."},
    {"id": 170, "unit": "Unit 4", "unitName": "American Political Ideologies and Beliefs", "concept": "Benchmark Polls", "question": "A benchmark poll is typically conducted:", "options": ["After an election", "Only by the media", "At the start of a campaign to establish baseline support", "During voting"], "answer": "C", "explanation": "Campaigns use benchmark polls to understand their starting position with voters."},
    {"id": 171, "unit": "Unit 4", "unitName": "American Political Ideologies and Beliefs", "concept": "Exit Polls", "question": "Exit polls are conducted:", "options": ["Before an election", "Only by mail", "As voters leave polling places on Election Day", "A month after elections"], "answer": "C", "explanation": "Media organizations survey voters leaving polls to project outcomes and analyze voting patterns."},
    {"id": 172, "unit": "Unit 4", "unitName": "American Political Ideologies and Beliefs", "concept": "Tracking Polls", "question": "Tracking polls differ from other polls because they:", "options": ["Are conducted only once", "Survey the same group over time to detect trends", "Use very small samples", "Are always accurate"], "answer": "B", "explanation": "Tracking polls continuously monitor public opinion to identify changes over time."},
    {"id": 173, "unit": "Unit 4", "unitName": "American Political Ideologies and Beliefs", "concept": "Political Ideology Formation (Stimulus)", "question": "A survey shows that 65% of Americans aged 18-29 support government-funded healthcare, while only 35% of those over 65 do. This difference is best explained by:", "options": ["Sampling error", "Random chance", "Generational differences in political socialization", "Media bias"], "answer": "C", "explanation": "Different generations often develop different political attitudes based on their experiences."},
    {"id": 174, "unit": "Unit 4", "unitName": "American Political Ideologies and Beliefs", "concept": "Party Identification", "question": "The strongest predictor of how someone will vote is:", "options": ["Their income level", "Their education level", "Their party identification", "Their age"], "answer": "C", "explanation": "Party identification is the single best predictor of vote choice."},
    {"id": 175, "unit": "Unit 4", "unitName": "American Political Ideologies and Beliefs", "concept": "Realignment", "question": "A political realignment occurs when:", "options": ["An election is contested", "A third party wins", "Voter turnout decreases", "Voters shift party loyalties in a lasting way, often due to major issues"], "answer": "D", "explanation": "Realignments mark fundamental, lasting shifts in the party system."},
    {"id": 176, "unit": "Unit 4", "unitName": "American Political Ideologies and Beliefs", "concept": "Social Conservatism", "question": "A social conservative would most likely support:", "options": ["Legalization of all drugs", "Expanding LGBTQ+ protections", "Eliminating religious institutions", "Traditional family values and opposition to abortion"], "answer": "D", "explanation": "Social conservatives emphasize traditional moral and family values."},
    {"id": 177, "unit": "Unit 4", "unitName": "American Political Ideologies and Beliefs", "concept": "Progressivism", "question": "Progressives generally advocate for:", "options": ["Government-led social and economic reform to address inequality", "Maintaining the status quo", "Eliminating all regulations", "Reducing the size of government"], "answer": "A", "explanation": "Progressives push for systemic reforms to create a more equitable society."},
    {"id": 178, "unit": "Unit 4", "unitName": "American Political Ideologies and Beliefs", "concept": "Tax Policy Views", "question": "A progressive tax system means:", "options": ["Everyone pays the same rate", "Lower-income earners pay more", "Taxes are voluntary", "Higher-income earners pay a higher percentage"], "answer": "D", "explanation": "Progressive taxation increases rates as income rises."},
    {"id": 179, "unit": "Unit 4", "unitName": "American Political Ideologies and Beliefs", "concept": "Flat Tax", "question": "Supporters of a flat tax argue that it:", "options": ["Is more complex than the current system", "Only benefits the wealthy", "Should replace all government revenue", "Is simpler and treats all taxpayers equally"], "answer": "D", "explanation": "Flat tax advocates emphasize simplicity and equal treatment."},
    {"id": 180, "unit": "Unit 4", "unitName": "American Political Ideologies and Beliefs", "concept": "Policy Mood (Stimulus)", "question": "A graph shows public support for government spending increasing during a recession and decreasing during economic booms. This pattern demonstrates:", "options": ["The public's policy mood shifts in response to economic conditions", "People always want more spending", "Polls are unreliable", "The media controls public opinion"], "answer": "A", "explanation": "Public opinion on government's role often shifts with economic circumstances."},
    {"id": 181, "unit": "Unit 5", "unitName": "Political Participation", "concept": "Voter Turnout", "question": "Which factor most increases voter turnout?", "options": ["Being young", "Higher education levels", "Living in a rural area", "Registering on Election Day"], "answer": "B", "explanation": "Education is one of the strongest predictors of voter participation."},
    {"id": 182, "unit": "Unit 5", "unitName": "Political Participation", "concept": "Primary Elections", "question": "In a closed primary election:", "options": ["Any voter can participate regardless of party", "The general public votes for all candidates", "Only registered party members can vote in that party's primary", "There are no candidates"], "answer": "C", "explanation": "Closed primaries restrict participation to voters registered with the party."},
    {"id": 183, "unit": "Unit 5", "unitName": "Political Participation", "concept": "Open Primaries", "question": "An open primary allows:", "options": ["Voters to participate in any party's primary regardless of registration", "Only party members to vote", "Only independents to vote", "Candidates from all parties on one ballot"], "answer": "A", "explanation": "Open primaries do not require voters to be registered with a particular party."},
    {"id": 184, "unit": "Unit 5", "unitName": "Political Participation", "concept": "Electoral College", "question": "The Electoral College system means that presidential elections are decided by:", "options": ["Electoral votes allocated to states based on congressional representation", "Direct popular vote", "A vote in Congress", "The Supreme Court"], "answer": "A", "explanation": "Each state gets electors equal to its total number of House and Senate members."},
    {"id": 185, "unit": "Unit 5", "unitName": "Political Participation", "concept": "Winner-Take-All", "question": "Most states use a winner-take-all system for the Electoral College, meaning:", "options": ["All of a state's electoral votes go to the candidate who wins the popular vote in that state", "Electoral votes are split proportionally", "Only the winning party's voters count", "Third parties always get some votes"], "answer": "A", "explanation": "In 48 states, the popular vote winner receives all electoral votes."},
    {"id": 186, "unit": "Unit 5", "unitName": "Political Participation", "concept": "Two-Party System", "question": "The United States has a two-party system primarily because of:", "options": ["The Constitution mandating two parties", "Federal law banning third parties", "Voters preferring only two choices", "Winner-take-all elections and single-member districts"], "answer": "D", "explanation": "Single-member districts with plurality voting (Duverger's Law) favor two major parties."},
    {"id": 187, "unit": "Unit 5", "unitName": "Political Participation", "concept": "Third Parties", "question": "Third parties in the U.S. are significant because they:", "options": ["Often win presidential elections", "Are constitutionally protected", "Have equal media coverage", "Bring new issues to the political agenda and can influence major party platforms"], "answer": "D", "explanation": "Third parties serve as idea incubators even though they rarely win major offices."},
    {"id": 188, "unit": "Unit 5", "unitName": "Political Participation", "concept": "Interest Groups", "question": "Interest groups differ from political parties because they:", "options": ["Seek to influence policy without running candidates", "Run candidates for office", "Have no political goals", "Are funded by the government"], "answer": "A", "explanation": "Interest groups lobby and advocate for policy positions rather than nominating candidates."},
    {"id": 189, "unit": "Unit 5", "unitName": "Political Participation", "concept": "PACs", "question": "Political Action Committees (PACs) are organizations that:", "options": ["Run for political office", "Raise money to donate directly to candidates' campaigns", "Are illegal", "Can donate unlimited amounts to candidates"], "answer": "B", "explanation": "PACs pool contributions to support or oppose candidates within legal contribution limits."},
    {"id": 190, "unit": "Unit 5", "unitName": "Political Participation", "concept": "Super PACs", "question": "Super PACs differ from traditional PACs because they:", "options": ["Can raise and spend unlimited money on independent expenditures but cannot coordinate with campaigns", "Cannot accept any donations", "Can donate directly to candidates", "Are run by the government"], "answer": "A", "explanation": "Super PACs emerged after Citizens United and SpeechNow.org v. FEC."},
    {"id": 191, "unit": "Unit 5", "unitName": "Political Participation", "concept": "Lobbying", "question": "Lobbying is the practice of:", "options": ["Running for office", "Voting in elections", "Filing lawsuits", "Attempting to influence government officials on behalf of an interest group or cause"], "answer": "D", "explanation": "Lobbyists represent various interests and try to shape legislation and policy."},
    {"id": 192, "unit": "Unit 5", "unitName": "Political Participation", "concept": "Motor Voter Act", "question": "The National Voter Registration Act (Motor Voter, 1993) was designed to:", "options": ["Make it easier to register to vote at government offices like the DMV", "Eliminate voter registration", "Allow online voting", "Require voter ID"], "answer": "A", "explanation": "The Act simplified registration by requiring states to offer it at motor vehicle and other agencies."},
    {"id": 193, "unit": "Unit 5", "unitName": "Political Participation", "concept": "Voter ID Laws", "question": "Critics of strict voter ID laws argue that they:", "options": ["Increase turnout", "Have no effect", "Disproportionately burden low-income and minority voters", "Are required by the Constitution"], "answer": "C", "explanation": "Opponents say strict ID requirements create barriers for those less likely to have photo identification."},
    {"id": 194, "unit": "Unit 5", "unitName": "Political Participation", "concept": "Gerrymandering Effects", "question": "Partisan gerrymandering can reduce electoral competition by:", "options": ["Creating more competitive districts", "Drawing districts where one party has a safe majority", "Eliminating the Electoral College", "Increasing voter turnout"], "answer": "B", "explanation": "Gerrymandered districts often guarantee outcomes, reducing competition."},
    {"id": 195, "unit": "Unit 5", "unitName": "Political Participation", "concept": "Campaign Finance", "question": "The Federal Election Campaign Act (FECA) requires:", "options": ["Disclosure of campaign contributions and spending", "Unlimited donations to candidates", "No limits on anything", "Government-funded campaigns only"], "answer": "A", "explanation": "FECA established reporting requirements and contribution limits."},
    {"id": 196, "unit": "Unit 5", "unitName": "Political Participation", "concept": "Buckley v. Valeo", "question": "Buckley v. Valeo (1976) ruled that:", "options": ["All campaign spending can be limited", "Corporations cannot participate in politics", "Spending money on campaigns is a form of protected speech", "Public financing is unconstitutional"], "answer": "C", "explanation": "The Court ruled that limiting campaign expenditures violates the First Amendment."},
    {"id": 197, "unit": "Unit 5", "unitName": "Political Participation", "concept": "Media in Campaigns", "question": "The media's role in campaigns includes all of the following EXCEPT:", "options": ["Setting the agenda", "Fact-checking claims", "Providing free airtime to all candidates equally", "Hosting debates"], "answer": "C", "explanation": "Media do not provide free, equal airtime; paid advertising and earned media coverage are unequal."},
    {"id": 198, "unit": "Unit 5", "unitName": "Political Participation", "concept": "Horse Race Coverage", "question": "Horse race journalism in political campaigns focuses on:", "options": ["Who is ahead in polls rather than policy substance", "Policy details", "Historical context", "Legislative analysis"], "answer": "A", "explanation": "Horse race coverage emphasizes polling numbers and campaign strategy over issues."},
    {"id": 199, "unit": "Unit 5", "unitName": "Political Participation", "concept": "Swing States", "question": "Swing states are important in presidential elections because they:", "options": ["Could be won by either major party candidate", "Always vote for the same party", "Have the most electoral votes", "Are the smallest states"], "answer": "A", "explanation": "Candidates focus resources on competitive states that could tip the electoral college."},
    {"id": 200, "unit": "Unit 5", "unitName": "Political Participation", "concept": "Midterm Elections", "question": "Midterm elections typically result in:", "options": ["Higher turnout than presidential elections", "The president's party gaining seats", "The president's party losing seats in Congress", "No change in party control"], "answer": "C", "explanation": "The president's party historically loses congressional seats during midterms."},
    {"id": 201, "unit": "Unit 5", "unitName": "Political Participation", "concept": "Ballot Initiatives", "question": "A ballot initiative allows:", "options": ["The president to propose legislation", "Congress to override state laws", "Citizens to vote directly on proposed laws or amendments", "Judges to create new laws"], "answer": "C", "explanation": "Ballot initiatives are a form of direct democracy available in many states."},
    {"id": 202, "unit": "Unit 5", "unitName": "Political Participation", "concept": "Recall Elections", "question": "A recall election allows voters to:", "options": ["Elect additional representatives", "Override a Supreme Court decision", "Remove an elected official before their term ends", "Amend the Constitution"], "answer": "C", "explanation": "Recalls are a mechanism for voters to hold officials accountable between regular elections."},
    {"id": 203, "unit": "Unit 5", "unitName": "Political Participation", "concept": "Party Platforms", "question": "A political party's platform is:", "options": ["A statement of the party's positions on issues and policy goals", "Its list of candidates", "Its fundraising strategy", "Its organizational chart"], "answer": "A", "explanation": "The platform outlines the party's official stances on major issues."},
    {"id": 204, "unit": "Unit 5", "unitName": "Political Participation", "concept": "National Conventions", "question": "National party conventions serve to:", "options": ["Pass legislation", "Formally nominate presidential candidates and adopt party platforms", "Elect members of Congress", "Confirm judicial appointments"], "answer": "B", "explanation": "Conventions are the culmination of the nomination process for presidential candidates."},
    {"id": 205, "unit": "Unit 5", "unitName": "Political Participation", "concept": "Caucuses", "question": "Iowa's caucus system differs from a primary because it involves:", "options": ["Secret ballot voting at polling places", "Only elected officials voting", "Voters gathering in groups to publicly discuss and select candidates", "No voter participation"], "answer": "C", "explanation": "Caucuses are participatory meetings rather than simple secret-ballot elections."},
    {"id": 206, "unit": "Unit 5", "unitName": "Political Participation", "concept": "Delegate Selection", "question": "In the Democratic Party, superdelegates are:", "options": ["Elected through primaries", "Required to follow state primary results", "Chosen by the Republican Party", "Party leaders and elected officials who can support any candidate at the convention"], "answer": "D", "explanation": "Superdelegates are unpledged delegates with independent voting discretion at the convention."},
    {"id": 207, "unit": "Unit 5", "unitName": "Political Participation", "concept": "Social Media in Politics", "question": "Social media has changed political campaigns by:", "options": ["Eliminating the need for fundraising", "Allowing candidates to communicate directly with voters and mobilize support", "Replacing traditional media entirely", "Making campaigns more expensive"], "answer": "B", "explanation": "Social media enables direct engagement, rapid fundraising, and grassroots mobilization."},
    {"id": 208, "unit": "Unit 5", "unitName": "Political Participation", "concept": "Negative Campaigning", "question": "Research on negative campaigning suggests that it:", "options": ["Has no effect on voters", "Always increases voter turnout", "Is illegal", "Can be effective in lowering opponents' favorability but may also depress turnout"], "answer": "D", "explanation": "Negative ads can shape perceptions but may also contribute to voter cynicism."},
    {"id": 209, "unit": "Unit 5", "unitName": "Political Participation", "concept": "Issue Networks", "question": "Issue networks differ from iron triangles because they:", "options": ["Are more rigid and exclusive", "Only involve government officials", "Include a broader, more fluid range of participants involved in a policy area", "Never change membership"], "answer": "C", "explanation": "Issue networks are more open and dynamic than the closed iron triangle relationship."},
    {"id": 210, "unit": "Unit 5", "unitName": "Political Participation", "concept": "Rational Choice Voting", "question": "The rational choice model suggests voters will:", "options": ["Always vote for the incumbent", "Vote randomly", "Vote for the candidate whose policies best serve their self-interest", "Never participate in elections"], "answer": "C", "explanation": "Rational choice theory assumes voters make calculated decisions to maximize their benefit."},
    {"id": 211, "unit": "Unit 5", "unitName": "Political Participation", "concept": "Retrospective Voting", "question": "Retrospective voting means voters:", "options": ["Evaluate candidates based on past performance", "Look at candidates' future promises", "Only vote in retrospect", "Never consider incumbents"], "answer": "A", "explanation": "Retrospective voters judge whether things have gotten better or worse under current leadership."},
    {"id": 212, "unit": "Unit 5", "unitName": "Political Participation", "concept": "Prospective Voting", "question": "Prospective voting involves:", "options": ["Voting based on past performance", "Voting based on what a candidate promises to do in the future", "Random selection", "Straight-ticket voting only"], "answer": "B", "explanation": "Prospective voters choose based on candidates' proposed policies."},
    {"id": 213, "unit": "Unit 5", "unitName": "Political Participation", "concept": "Straight-Ticket Voting", "question": "Straight-ticket voting refers to:", "options": ["Splitting votes between parties", "Voting for candidates of the same party for all offices on the ballot", "Voting only for president", "Not voting at all"], "answer": "B", "explanation": "Some voters choose all candidates from one party."},
    {"id": 214, "unit": "Unit 5", "unitName": "Political Participation", "concept": "Split-Ticket Voting", "question": "Split-ticket voting occurs when a voter:", "options": ["Only votes in primaries", "Votes for candidates of different parties for various offices", "Writes in candidates", "Votes for the same party throughout"], "answer": "B", "explanation": "Split-ticket voters may choose a Republican president and a Democratic senator, for example."},
    {"id": 215, "unit": "Unit 5", "unitName": "Political Participation", "concept": "Party Dealignment", "question": "Party dealignment refers to:", "options": ["Voters becoming more strongly partisan", "A decline in party loyalty and an increase in independent voters", "The merger of two parties", "A constitutional amendment about parties"], "answer": "B", "explanation": "Dealignment occurs when voters move away from strong party identification."},
    {"id": 216, "unit": "Unit 5", "unitName": "Political Participation", "concept": "Linkage Institutions", "question": "Linkage institutions connect citizens to government. Examples include:", "options": ["Only the Supreme Court", "Only the military", "Political parties, interest groups, media, and elections", "Only bureaucratic agencies"], "answer": "C", "explanation": "Linkage institutions are the channels through which public preferences are communicated to government."},
    {"id": 217, "unit": "Unit 5", "unitName": "Political Participation", "concept": "Get-Out-the-Vote (GOTV)", "question": "Get-out-the-vote efforts are most effective when they:", "options": ["Use television ads alone", "Involve personal contact such as door-to-door canvassing", "Ignore social media", "Target only wealthy voters"], "answer": "B", "explanation": "Research shows personal, face-to-face contact is the most effective GOTV method."},
    {"id": 218, "unit": "Unit 5", "unitName": "Political Participation", "concept": "Civic Participation", "question": "Beyond voting, citizens participate in democracy through:", "options": ["Only paying taxes", "Watching the news only", "Contacting officials, protesting, volunteering, and joining interest groups", "Doing nothing"], "answer": "C", "explanation": "Political participation encompasses many activities beyond the ballot box."},
    {"id": 219, "unit": "Unit 5", "unitName": "Political Participation", "concept": "Voter Turnout Factors (Stimulus)", "question": "Data shows that voter turnout in the 2020 presidential election was approximately 66%, the highest since 1900. Which factor best explains the increase?", "options": ["Fewer candidates running", "Mandatory voting laws", "Elimination of the Electoral College", "Expanded access to early and mail-in voting during the pandemic"], "answer": "D", "explanation": "The pandemic prompted expanded mail-in and early voting options, increasing accessibility."},
    {"id": 220, "unit": "Unit 5", "unitName": "Political Participation", "concept": "Campaign Strategy (Stimulus)", "question": "A campaign manager sees polling data showing their candidate trails by 15 points among suburban women. The BEST strategic response would be to:", "options": ["Ignore that demographic entirely", "Focus resources on a demographic where the candidate already leads", "Withdraw from the race", "Develop targeted messaging and outreach to suburban women on issues they prioritize"], "answer": "D", "explanation": "Effective campaigns use data to target persuadable demographics with relevant messaging."},
    {"id": 221, "unit": "Unit 5", "unitName": "Political Participation", "concept": "26th Amendment", "question": "The 26th Amendment lowered the voting age to:", "options": ["18", "21", "16", "25"], "answer": "A", "explanation": "Ratified in 1971, it gave 18-year-olds the right to vote, partly in response to the Vietnam War draft."},
    {"id": 222, "unit": "Unit 5", "unitName": "Political Participation", "concept": "Franking Privilege", "question": "The franking privilege allows members of Congress to:", "options": ["Vote in other districts", "Send mail to constituents at no personal cost, using government funds", "Accept unlimited campaign donations", "Skip committee meetings"], "answer": "B", "explanation": "Franking helps incumbents maintain contact with constituents using taxpayer-funded mailings."},
    {"id": 223, "unit": "Unit 5", "unitName": "Political Participation", "concept": "Soft Money", "question": "Before the Bipartisan Campaign Reform Act (BCRA), 'soft money' referred to:", "options": ["Money donated directly to candidates", "Government-funded campaign grants", "Unregulated donations to political parties for party-building activities", "Small individual contributions"], "answer": "C", "explanation": "BCRA (McCain-Feingold) banned unlimited soft money contributions to national parties."},
    {"id": 224, "unit": "Unit 5", "unitName": "Political Participation", "concept": "Dark Money", "question": "Dark money in politics refers to:", "options": ["Government-funded campaigns", "Political spending by nonprofit organizations that do not disclose donors", "PAC contributions", "Small-dollar donations"], "answer": "B", "explanation": "Dark money groups can influence elections without revealing their funding sources."},
    {"id": 225, "unit": "Unit 5", "unitName": "Political Participation", "concept": "Voter Suppression", "question": "Historically, voter suppression tactics included:", "options": ["Expanding early voting", "Automatic voter registration", "Same-day registration", "Poll taxes, literacy tests, and grandfather clauses"], "answer": "D", "explanation": "These tactics were used primarily to prevent African Americans from voting in the Jim Crow era."},
    {"id": 226, "unit": "Unit 5", "unitName": "Political Participation", "concept": "Battleground Strategy (Stimulus)", "question": "A map shows a presidential candidate spending 80% of campaign funds in 6 states. This strategy reflects:", "options": ["A national campaign approach", "The importance of swing states in the Electoral College system", "A focus on safe states", "Ignoring the Electoral College"], "answer": "B", "explanation": "Candidates concentrate resources in competitive states that could determine the electoral outcome."},
    {"id": 227, "unit": "Unit 5", "unitName": "Political Participation", "concept": "Front-Loading", "question": "Front-loading in the primary process refers to:", "options": ["Candidates spending all money at the end", "States moving their primaries to earlier dates to gain more influence", "Media ignoring early states", "Superdelegates voting first"], "answer": "B", "explanation": "States schedule early primaries to attract candidate attention and media coverage."},
    {"id": 228, "unit": "Unit 5", "unitName": "Political Participation", "concept": "527 Organizations", "question": "527 organizations are:", "options": ["Government agencies", "Part of the judicial branch", "Local school boards", "Tax-exempt groups that engage in political activities like voter mobilization"], "answer": "D", "explanation": "Named after the tax code section, 527s can raise unlimited funds for political activities."},
    {"id": 229, "unit": "Unit 1", "unitName": "Foundations of American Democracy", "concept": "Federalism Debate (Stimulus)", "question": "\"The powers delegated by the proposed Constitution to the federal government are few and defined. Those which are to remain in the State governments are numerous and indefinite.\" — James Madison, Federalist No. 45\n\nMadison is arguing that:", "options": ["The federal government will dominate the states", "The Constitution eliminates state power", "Federal power is unlimited", "State governments will retain significant authority under the new Constitution"], "answer": "D", "explanation": "Madison sought to reassure skeptics that states would keep broad powers."},
    {"id": 230, "unit": "Unit 1", "unitName": "Foundations of American Democracy", "concept": "Supremacy in Practice", "question": "When a state law conflicts with a valid federal law, what happens?", "options": ["The state law takes precedence", "Both laws are enforced equally", "The federal law prevails under the Supremacy Clause", "The Supreme Court automatically intervenes"], "answer": "C", "explanation": "Article VI establishes that federal law overrides conflicting state legislation."},
    {"id": 231, "unit": "Unit 1", "unitName": "Foundations of American Democracy", "concept": "Constitutional Interpretation", "question": "The 'living Constitution' approach holds that the Constitution should be:", "options": ["Interpreted exactly as written", "Never amended", "Read only by judges", "Interpreted in light of contemporary values and circumstances"], "answer": "D", "explanation": "Living constitutionalists believe the document must evolve with changing times."},
    {"id": 232, "unit": "Unit 1", "unitName": "Foundations of American Democracy", "concept": "Originalism", "question": "Originalists believe the Constitution should be interpreted based on:", "options": ["Modern societal needs", "International law", "The original meaning understood at the time of ratification", "Congressional intent alone"], "answer": "C", "explanation": "Originalists seek to apply the Framers' intended meaning."},
    {"id": 233, "unit": "Unit 1", "unitName": "Foundations of American Democracy", "concept": "Confederal vs. Federal", "question": "A confederal system differs from a federal system because in a confederal system:", "options": ["The central government is all-powerful", "Power resides primarily with the individual states, with a weak central authority", "There is no government", "States do not exist"], "answer": "B", "explanation": "Confederal systems give most power to subnational units, unlike federal systems."},
    {"id": 234, "unit": "Unit 1", "unitName": "Foundations of American Democracy", "concept": "Mandates and Conditions", "question": "Federal mandates differ from conditions of aid because mandates:", "options": ["Require state action regardless of federal funding", "Are voluntary", "Only apply to the judiciary", "Do not affect state governments"], "answer": "A", "explanation": "Mandates compel compliance whether or not states receive federal funds."},
    {"id": 235, "unit": "Unit 1", "unitName": "Foundations of American Democracy", "concept": "Interstate Commerce", "question": "The Gibbons v. Ogden (1824) decision strengthened federal power by ruling that:", "options": ["States control all commerce", "Congress has broad authority to regulate interstate commerce including navigation", "Only the president can regulate trade", "Commerce stops at state borders"], "answer": "B", "explanation": "The ruling broadly defined 'commerce' and affirmed federal power over interstate trade."},
    {"id": 236, "unit": "Unit 1", "unitName": "Foundations of American Democracy", "concept": "New Federalism", "question": "New Federalism, championed by Presidents Nixon and Reagan, emphasized:", "options": ["Expanding federal programs", "Eliminating the states", "Creating new federal agencies", "Shifting power and responsibility back to state governments"], "answer": "D", "explanation": "New Federalism sought to reduce federal control and return authority to the states."},
    {"id": 237, "unit": "Unit 2", "unitName": "Interactions Among Branches", "concept": "Congressional Leadership", "question": "The Senate Majority Leader is influential because they:", "options": ["Are constitutionally the head of the Senate", "Can override presidential vetoes", "Control the Senate's legislative schedule and floor agenda", "Appoint Supreme Court justices"], "answer": "C", "explanation": "The Majority Leader shapes what legislation reaches the Senate floor."},
    {"id": 238, "unit": "Unit 2", "unitName": "Interactions Among Branches", "concept": "Bicameralism (Stimulus)", "question": "The Framers created a bicameral legislature to:", "options": ["Provide representation based on both population and state equality while checking legislative power", "Speed up the legislative process", "Give the president more power", "Limit judicial review"], "answer": "A", "explanation": "The two chambers represent different constituencies and check each other."},
    {"id": 239, "unit": "Unit 2", "unitName": "Interactions Among Branches", "concept": "Treaty Power", "question": "Treaties negotiated by the president must be approved by:", "options": ["A two-thirds vote of the Senate", "A simple majority of the House", "A simple majority of the Senate", "A two-thirds vote of both chambers"], "answer": "A", "explanation": "The Constitution requires a two-thirds Senate vote to ratify treaties."},
    {"id": 240, "unit": "Unit 2", "unitName": "Interactions Among Branches", "concept": "Recess Appointments", "question": "The president can make recess appointments when:", "options": ["The Senate is in recess, temporarily filling vacancies without Senate confirmation", "Congress is in session", "The Supreme Court approves", "The House requests it"], "answer": "A", "explanation": "Recess appointments allow the president to fill positions when the Senate is unavailable."},
    {"id": 241, "unit": "Unit 2", "unitName": "Interactions Among Branches", "concept": "Legislative Riders", "question": "A rider attached to a bill is:", "options": ["Always relevant to the main bill", "Required by the Constitution", "An unrelated provision added to a bill likely to pass", "Only used in the Senate"], "answer": "C", "explanation": "Riders allow legislators to advance provisions by attaching them to popular legislation."},
    {"id": 242, "unit": "Unit 2", "unitName": "Interactions Among Branches", "concept": "Bureaucratic Accountability", "question": "Which method allows Congress to influence bureaucratic behavior after a law is enacted?", "options": ["Congressional oversight through hearings, budget control, and reauthorization", "Only the president can influence agencies", "Judicial appointments", "State government pressure"], "answer": "A", "explanation": "Congress uses multiple tools to monitor and direct agency implementation."},
    {"id": 243, "unit": "Unit 2", "unitName": "Interactions Among Branches", "concept": "Whistleblower Protections", "question": "Whistleblower protection laws encourage government employees to:", "options": ["Report waste, fraud, and abuse without fear of retaliation", "Always agree with their supervisors", "Leak classified information to the press", "Ignore problems"], "answer": "A", "explanation": "These laws protect employees who expose government wrongdoing."},
    {"id": 244, "unit": "Unit 2", "unitName": "Interactions Among Branches", "concept": "Line-Item Veto", "question": "The Supreme Court struck down the line-item veto in Clinton v. City of New York because it:", "options": ["Was too expensive", "Was unnecessary", "Violated the Presentment Clause by allowing the president to unilaterally amend legislation", "Helped Congress too much"], "answer": "C", "explanation": "The Court ruled the president cannot selectively cancel parts of enacted legislation."},
    {"id": 245, "unit": "Unit 3", "unitName": "Civil Liberties and Civil Rights", "concept": "Establishment Clause Case (Stimulus)", "question": "A city places a nativity scene on government property alongside secular holiday decorations. Under the Lemon test, a court would most likely:", "options": ["Always strike it down", "Require a referendum", "Ignore the case", "Allow it because the overall display has a secular purpose"], "answer": "D", "explanation": "Mixed displays with secular elements may pass the Lemon test's secular purpose requirement."},
    {"id": 246, "unit": "Unit 3", "unitName": "Civil Liberties and Civil Rights", "concept": "Free Speech Limits", "question": "Which type of speech receives the LEAST First Amendment protection?", "options": ["Obscenity", "Political speech", "Commercial speech", "Symbolic speech"], "answer": "A", "explanation": "Obscenity, as defined by the Miller test, receives no First Amendment protection."},
    {"id": 247, "unit": "Unit 3", "unitName": "Civil Liberties and Civil Rights", "concept": "Commercial Speech", "question": "Commercial speech receives:", "options": ["No protection", "The same protection as political speech", "Limited protection — it can be regulated if misleading", "Absolute protection"], "answer": "C", "explanation": "The government can regulate false or misleading advertising, unlike political speech."},
    {"id": 248, "unit": "Unit 3", "unitName": "Civil Liberties and Civil Rights", "concept": "Gitlow v. New York", "question": "Gitlow v. New York (1925) was significant because it:", "options": ["Ended free speech protections", "Began the process of incorporating the Bill of Rights to apply to states through the 14th Amendment", "Overturned Marbury v. Madison", "Established the exclusionary rule"], "answer": "B", "explanation": "Gitlow was the first case to apply a Bill of Rights protection to states via the 14th Amendment."},
    {"id": 249, "unit": "Unit 3", "unitName": "Civil Liberties and Civil Rights", "concept": "Korematsu v. United States", "question": "Korematsu v. United States (1944) upheld:", "options": ["The right to free speech during wartime", "School desegregation", "The exclusionary rule", "Japanese American internment during World War II"], "answer": "D", "explanation": "The Court allowed internment as a wartime necessity, a decision now widely condemned."},
    {"id": 250, "unit": "Unit 3", "unitName": "Civil Liberties and Civil Rights", "concept": "Shelby County v. Holder", "question": "Shelby County v. Holder (2013) struck down a key provision of the Voting Rights Act, which:", "options": ["Banned all forms of voter ID", "Eliminated the Electoral College", "Required certain states to get federal approval before changing voting laws", "Established automatic voter registration"], "answer": "C", "explanation": "The Court invalidated the preclearance formula, weakening federal oversight of voting changes."},
    {"id": 251, "unit": "Unit 3", "unitName": "Civil Liberties and Civil Rights", "concept": "Obergefell v. Hodges", "question": "Obergefell v. Hodges (2015) ruled that:", "options": ["States can ban same-sex marriage", "Same-sex marriage is a constitutional right under the 14th Amendment", "Marriage is not a constitutional issue", "Only Congress can legalize same-sex marriage"], "answer": "B", "explanation": "The Court held that the right to marry is guaranteed to same-sex couples."},
    {"id": 252, "unit": "Unit 3", "unitName": "Civil Liberties and Civil Rights", "concept": "Disparate Impact", "question": "Disparate impact occurs when:", "options": ["A law explicitly discriminates", "A facially neutral law or practice disproportionately affects a protected group", "Everyone is treated identically", "No discrimination exists"], "answer": "B", "explanation": "Disparate impact looks at outcomes rather than intent."},
    {"id": 253, "unit": "Unit 4", "unitName": "American Political Ideologies and Beliefs", "concept": "Ideology and Demographics", "question": "Which demographic group has historically been most likely to identify as Democratic?", "options": ["African Americans", "White evangelical Christians", "Rural white voters", "Business executives"], "answer": "A", "explanation": "African Americans have overwhelmingly supported the Democratic Party since the 1960s."},
    {"id": 254, "unit": "Unit 4", "unitName": "American Political Ideologies and Beliefs", "concept": "Media Framing", "question": "Media framing refers to:", "options": ["Journalists lying about events", "Censoring all political content", "Reporters running for office", "How the media presents a story, influencing audience interpretation"], "answer": "D", "explanation": "The way a story is framed can shape how the public perceives an issue."},
    {"id": 255, "unit": "Unit 4", "unitName": "American Political Ideologies and Beliefs", "concept": "Agenda Setting", "question": "The media's agenda-setting function means it:", "options": ["Tells people what to think", "Controls government policy", "Writes legislation", "Influences what issues people consider important by choosing which stories to cover"], "answer": "D", "explanation": "By selecting stories, the media shapes which issues receive public attention."},
    {"id": 256, "unit": "Unit 4", "unitName": "American Political Ideologies and Beliefs", "concept": "Priming", "question": "In media studies, priming refers to:", "options": ["Preparing candidates for debates", "Media coverage that makes certain issues more prominent in evaluating political figures", "Printing newspapers", "Polling before elections"], "answer": "B", "explanation": "Priming influences the criteria people use to judge politicians."},
    {"id": 257, "unit": "Unit 4", "unitName": "American Political Ideologies and Beliefs", "concept": "Selective Exposure", "question": "Selective exposure in media consumption means people tend to:", "options": ["Watch all news sources equally", "Avoid all news", "Seek out media that reinforces their existing beliefs", "Only read newspapers"], "answer": "C", "explanation": "People often choose information sources that confirm their pre-existing views."},
    {"id": 258, "unit": "Unit 4", "unitName": "American Political Ideologies and Beliefs", "concept": "Discretionary vs. Mandatory Spending (Stimulus)", "question": "A pie chart shows the federal budget with 60% mandatory spending and 30% discretionary spending. The largest component of mandatory spending is most likely:", "options": ["Social Security", "Defense", "Education", "NASA"], "answer": "A", "explanation": "Social Security is the single largest mandatory spending program."},
    {"id": 259, "unit": "Unit 4", "unitName": "American Political Ideologies and Beliefs", "concept": "Ideology and Age", "question": "Research generally shows that younger voters tend to be:", "options": ["More conservative on social issues", "More liberal on social issues than older voters", "Identical to older voters", "Completely apolitical"], "answer": "B", "explanation": "Younger generations have tended to be more progressive on social issues."},
    {"id": 260, "unit": "Unit 4", "unitName": "American Political Ideologies and Beliefs", "concept": "Economic Inequality Views", "question": "A person who believes the government should do more to reduce income inequality likely holds:", "options": ["Conservative views", "Liberal views", "Libertarian views", "No political views"], "answer": "B", "explanation": "Support for government action to reduce inequality is a core liberal position."},
    {"id": 261, "unit": "Unit 5", "unitName": "Political Participation", "concept": "Voter Registration Barriers", "question": "Which of the following is NOT a current barrier to voter registration in most states?", "options": ["Residency requirements", "Literacy tests", "Registration deadlines before Election Day", "Lack of same-day registration"], "answer": "B", "explanation": "Literacy tests were banned by the Voting Rights Act of 1965."},
    {"id": 262, "unit": "Unit 5", "unitName": "Political Participation", "concept": "Political Efficacy", "question": "Political efficacy refers to:", "options": ["The efficiency of government operations", "A person's belief that their political participation matters and can influence government", "Voter apathy", "Government effectiveness"], "answer": "B", "explanation": "High political efficacy is associated with greater civic participation."},
    {"id": 263, "unit": "Unit 5", "unitName": "Political Participation", "concept": "Incumbency and Fundraising (Stimulus)", "question": "Data shows that incumbents raise on average three times more campaign funds than challengers. This primarily occurs because:", "options": ["Challengers are not allowed to fundraise", "The FEC limits challenger fundraising", "Donors prefer to contribute to incumbents who already have power and influence", "Incumbents use government funds"], "answer": "C", "explanation": "Incumbents' existing relationships and influence make them more attractive to donors."},
    {"id": 264, "unit": "Unit 5", "unitName": "Political Participation", "concept": "Proportional Representation", "question": "Under a proportional representation system, seats are allocated based on:", "options": ["The percentage of votes each party receives", "Winner-take-all in each district", "Only the top two parties", "Random selection"], "answer": "A", "explanation": "Proportional representation gives parties seats in proportion to their vote share."},
    {"id": 265, "unit": "Unit 5", "unitName": "Political Participation", "concept": "Runoff Elections", "question": "A runoff election is held when:", "options": ["A candidate wins a majority", "The president requests it", "No candidate receives the required percentage of votes in the first round", "The Supreme Court orders it"], "answer": "C", "explanation": "Runoffs ensure the eventual winner has broader support."},
    {"id": 266, "unit": "Unit 5", "unitName": "Political Participation", "concept": "Citizens United Impact (Stimulus)", "question": "After Citizens United v. FEC (2010), total outside spending in federal elections increased from $338 million in 2008 to over $1 billion in 2012. This data best supports the argument that:", "options": ["The decision significantly increased the role of money in politics", "Campaign spending decreased", "The ruling had no effect", "Only individual spending increased"], "answer": "A", "explanation": "The dramatic increase in outside spending followed directly from the Court's ruling."},
    {"id": 267, "unit": "Unit 5", "unitName": "Political Participation", "concept": "Microtargeting", "question": "Microtargeting in political campaigns refers to:", "options": ["Advertising to everyone equally", "Using data analytics to identify and deliver tailored messages to specific voter segments", "Targeting only large cities", "Ignoring voter data"], "answer": "B", "explanation": "Campaigns use voter data to craft personalized outreach to specific demographic groups."},
    {"id": 268, "unit": "Unit 5", "unitName": "Political Participation", "concept": "Party Realignment Example", "question": "The election of 1932 is considered a realigning election because:", "options": ["Nothing changed", "Republicans gained strength", "It shifted many voters to the Democratic Party under FDR's New Deal coalition", "Third parties won"], "answer": "C", "explanation": "The Great Depression led to a lasting shift as FDR built a broad Democratic coalition."},
    {"id": 269, "unit": "Unit 1", "unitName": "Foundations of American Democracy", "concept": "Consent of the Governed", "question": "The principle that government derives its authority from the people is called:", "options": ["Totalitarianism", "Aristocracy", "Consent of the governed", "Theocracy"], "answer": "C", "explanation": "Democratic legitimacy depends on the consent of those being governed."},
    {"id": 270, "unit": "Unit 1", "unitName": "Foundations of American Democracy", "concept": "Shays' Rebellion", "question": "Shays' Rebellion demonstrated that the Articles of Confederation:", "options": ["Were effective at maintaining order", "Gave too much power to the military", "Could not effectively deal with domestic unrest", "Were popular with farmers"], "answer": "C", "explanation": "The uprising exposed the central government's inability to respond to crises."},
    {"id": 271, "unit": "Unit 2", "unitName": "Interactions Among Branches", "concept": "Impeachment Trial", "question": "During a presidential impeachment trial, who presides?", "options": ["The Speaker of the House", "The Chief Justice of the Supreme Court", "The Senate Majority Leader", "The Vice President"], "answer": "B", "explanation": "The Chief Justice presides when the Senate tries a president."},
    {"id": 272, "unit": "Unit 2", "unitName": "Interactions Among Branches", "concept": "Congressional Term Lengths", "question": "Members of the House serve terms of how many years?", "options": ["Four", "Six", "Two", "Eight"], "answer": "C", "explanation": "House members serve two-year terms, requiring frequent re-election."},
    {"id": 273, "unit": "Unit 2", "unitName": "Interactions Among Branches", "concept": "Senate Term Length", "question": "Senators serve terms of:", "options": ["Two years", "Four years", "Eight years", "Six years"], "answer": "D", "explanation": "Six-year terms give senators more insulation from short-term political pressures."},
    {"id": 274, "unit": "Unit 3", "unitName": "Civil Liberties and Civil Rights", "concept": "Brandenburg v. Ohio", "question": "Brandenburg v. Ohio (1969) established that speech can only be restricted if it:", "options": ["Is unpopular", "Offends anyone", "Is political in nature", "Incites imminent lawless action and is likely to produce such action"], "answer": "D", "explanation": "The Brandenburg test is the current standard for when speech can be punished."},
    {"id": 275, "unit": "Unit 3", "unitName": "Civil Liberties and Civil Rights", "concept": "Reasonable Expectation of Privacy", "question": "In Katz v. United States (1967), the Court ruled that the Fourth Amendment protects:", "options": ["Only physical spaces", "People's reasonable expectations of privacy, not just physical places", "Government buildings", "Public spaces"], "answer": "B", "explanation": "The ruling expanded Fourth Amendment protections beyond physical trespass."},
    {"id": 276, "unit": "Unit 4", "unitName": "American Political Ideologies and Beliefs", "concept": "Party Coalition Shifts", "question": "The ideological shift of the South from Democratic to Republican is an example of:", "options": ["Dealignment", "Third-party dominance", "Judicial activism", "Partisan realignment"], "answer": "D", "explanation": "The Southern realignment shifted conservative white voters to the Republican Party over decades."},
    {"id": 277, "unit": "Unit 4", "unitName": "American Political Ideologies and Beliefs", "concept": "Fiscal Conservative", "question": "A fiscal conservative would most likely support:", "options": ["Balanced budgets and reduced government spending", "Increasing government spending on social programs", "Higher taxes on all income levels", "Expanding entitlement programs"], "answer": "A", "explanation": "Fiscal conservatives prioritize lower spending and balanced budgets."},
    {"id": 278, "unit": "Unit 5", "unitName": "Political Participation", "concept": "Voter Turnout Comparison (Stimulus)", "question": "U.S. voter turnout (around 60% in presidential years) is lower than many other democracies. Which structural feature most contributes to this?", "options": ["Voter registration requirements that place the burden on individual citizens", "Mandatory voting", "The existence of the Senate", "Judicial elections"], "answer": "A", "explanation": "Unlike many democracies with automatic registration, the U.S. requires individuals to register."},
    {"id": 279, "unit": "Unit 5", "unitName": "Political Participation", "concept": "Grassroots Mobilization", "question": "Grassroots mobilization involves:", "options": ["Organizing ordinary citizens at the local level to advocate for political change", "Top-down directives from party leaders", "Only wealthy donors", "Government-funded campaigns"], "answer": "A", "explanation": "Grassroots efforts empower local citizens to participate in the political process."},
    {"id": 280, "unit": "Unit 1", "unitName": "Foundations of American Democracy", "concept": "Rule of Law", "question": "The rule of law means:", "options": ["Government leaders and citizens are bound by the same laws", "The president is above the law", "Only judges must follow the law", "Laws apply differently to each person"], "answer": "A", "explanation": "No one is above the law in a system governed by the rule of law."},
    {"id": 281, "unit": "Unit 2", "unitName": "Interactions Among Branches", "concept": "Cloture Vote", "question": "How many votes are needed to invoke cloture in the Senate?", "options": ["51", "67", "75", "60"], "answer": "D", "explanation": "Sixty senators must vote for cloture to end a filibuster."},
    {"id": 282, "unit": "Unit 2", "unitName": "Interactions Among Branches", "concept": "Markup Session", "question": "During a committee markup session, members:", "options": ["Debate the bill on the floor", "Send the bill to the president", "Amend and rewrite the bill line by line", "Conduct oversight hearings"], "answer": "C", "explanation": "Markup is the process where committee members revise legislation in detail."},
    {"id": 283, "unit": "Unit 3", "unitName": "Civil Liberties and Civil Rights", "concept": "Eminent Domain", "question": "The Fifth Amendment's Takings Clause requires the government to provide:", "options": ["Nothing when taking private property", "A replacement property", "Just compensation when taking private property for public use", "An apology"], "answer": "C", "explanation": "The government must fairly compensate owners when exercising eminent domain."},
    {"id": 284, "unit": "Unit 3", "unitName": "Civil Liberties and Civil Rights", "concept": "Double Jeopardy", "question": "The prohibition against double jeopardy means a person cannot be:", "options": ["Tried twice for the same offense by the same sovereign", "Arrested without a warrant", "Denied bail", "Forced to testify against a spouse"], "answer": "A", "explanation": "The Fifth Amendment protects individuals from being tried twice for the same crime."},
    {"id": 285, "unit": "Unit 4", "unitName": "American Political Ideologies and Beliefs", "concept": "Confirmation Bias", "question": "Confirmation bias in political beliefs means people tend to:", "options": ["Accept information that confirms their existing views and reject contradictory evidence", "Seek out diverse perspectives", "Change their minds frequently", "Ignore all political news"], "answer": "A", "explanation": "Confirmation bias reinforces existing beliefs and contributes to political polarization."},
    {"id": 286, "unit": "Unit 4", "unitName": "American Political Ideologies and Beliefs", "concept": "Polarization", "question": "Political polarization refers to:", "options": ["Everyone agreeing on policy", "The growing ideological distance between political parties and their supporters", "Reduced voter interest", "A third party emerging"], "answer": "B", "explanation": "Polarization makes compromise more difficult as parties move further apart ideologically."},
    {"id": 287, "unit": "Unit 5", "unitName": "Political Participation", "concept": "Absentee Voting", "question": "Absentee voting allows citizens to:", "options": ["Vote only if they have a valid excuse", "Cast their ballot before Election Day or by mail without being at a polling place", "Vote in multiple states", "Skip the registration process"], "answer": "B", "explanation": "Absentee and mail-in voting increase accessibility for those who cannot vote in person."},
    {"id": 288, "unit": "Unit 5", "unitName": "Political Participation", "concept": "Early Voting", "question": "Early voting provisions are designed to:", "options": ["Increase voter turnout by providing more convenient voting times", "Discourage voting", "Benefit only one party", "Replace Election Day"], "answer": "A", "explanation": "Early voting reduces barriers by giving people flexibility in when they cast their ballot."},
    {"id": 289, "unit": "Unit 1", "unitName": "Foundations of American Democracy", "concept": "Hobbes State of Nature", "question": "Thomas Hobbes described the state of nature as:", "options": ["A peaceful paradise", "A state of war where life is 'solitary, poor, nasty, brutish, and short'", "A democratic society", "A constitutional monarchy"], "answer": "B", "explanation": "Hobbes's bleak view of human nature justified a strong sovereign to maintain order."},
    {"id": 290, "unit": "Unit 2", "unitName": "Interactions Among Branches", "concept": "Power of Oversight (Stimulus)", "question": "A congressional committee subpoenas a cabinet secretary to testify about agency spending. This is an example of:", "options": ["Judicial review", "Executive privilege", "Gerrymandering", "Congressional oversight of the bureaucracy"], "answer": "D", "explanation": "Subpoenaing executive officials is a tool of congressional oversight."},
    {"id": 291, "unit": "Unit 3", "unitName": "Civil Liberties and Civil Rights", "concept": "Voting Rights Today (Stimulus)", "question": "After Shelby County v. Holder, several states passed new voting restrictions within weeks. Critics argue these laws:", "options": ["Expand voting access", "Disproportionately affect minority voters, undermining the Voting Rights Act's goals", "Have no effect", "Only affect federal elections"], "answer": "B", "explanation": "The removal of preclearance allowed states to enact potentially discriminatory voting changes."},
    {"id": 292, "unit": "Unit 4", "unitName": "American Political Ideologies and Beliefs", "concept": "Values and Ideology", "question": "Core American political values include:", "options": ["Individualism, equality of opportunity, free enterprise, and rule of law", "Only individual liberty", "Government control of all aspects of life", "Collectivism above individual rights"], "answer": "A", "explanation": "These shared values form the foundation of American political culture."},
    {"id": 293, "unit": "Unit 5", "unitName": "Political Participation", "concept": "Majority vs. Plurality", "question": "In a plurality election, the winner is the candidate who:", "options": ["Receives the most votes, even without a majority", "Receives more than 50% of the vote", "Wins a runoff", "Is selected by party leaders"], "answer": "A", "explanation": "Plurality means the most votes wins, even if it's less than a majority."},
    {"id": 294, "unit": "Unit 1", "unitName": "Foundations of American Democracy", "concept": "Compact Theory", "question": "The compact theory of government held that:", "options": ["The federal government created the states", "Only the president can interpret the Constitution", "Citizens have no rights", "The Constitution was an agreement among the states that they could leave"], "answer": "D", "explanation": "This theory, championed by Calhoun, argued states retained ultimate sovereignty."},
    {"id": 295, "unit": "Unit 2", "unitName": "Interactions Among Branches", "concept": "State of the Union", "question": "The State of the Union address allows the president to:", "options": ["Set the legislative agenda by outlining priorities to Congress and the public", "Pass laws", "Override Supreme Court decisions", "Declare war"], "answer": "A", "explanation": "The address is a powerful tool for shaping public and congressional attention."},
    {"id": 296, "unit": "Unit 3", "unitName": "Civil Liberties and Civil Rights", "concept": "Loving v. Virginia", "question": "Loving v. Virginia (1967) struck down:", "options": ["School segregation", "Poll taxes", "Jim Crow transportation laws", "Laws banning interracial marriage"], "answer": "D", "explanation": "The Court ruled that bans on interracial marriage violated equal protection and due process."},
    {"id": 297, "unit": "Unit 4", "unitName": "American Political Ideologies and Beliefs", "concept": "Political Culture", "question": "American political culture is characterized by widespread belief in:", "options": ["Aristocratic governance", "Democracy, individual rights, and equality of opportunity", "One-party rule", "Government ownership of all property"], "answer": "B", "explanation": "Most Americans share core democratic values even when they disagree on specific policies."},
    {"id": 298, "unit": "Unit 5", "unitName": "Political Participation", "concept": "Voter Fatigue", "question": "Voter fatigue can occur when:", "options": ["Elections are rare", "Only one candidate runs", "Voting is mandatory", "Frequent elections or lengthy ballots lead to decreased participation"], "answer": "D", "explanation": "Too many elections or complex ballots can lead voters to skip voting altogether."},
    {"id": 299, "unit": "Unit 1", "unitName": "Foundations of American Democracy", "concept": "Federalist vs. Anti-Federalist (Stimulus)", "question": "\"A bill of rights is what the people are entitled to against every government on earth.\" — Thomas Jefferson\n\nThis quote most closely aligns with the views of the:", "options": ["Federalists", "Monarchists", "Anarchists", "Anti-Federalists"], "answer": "D", "explanation": "Anti-Federalists and Jefferson insisted on explicit protections for individual rights."},
    {"id": 300, "unit": "Unit 2", "unitName": "Interactions Among Branches", "concept": "Senate Judiciary Committee", "question": "The Senate Judiciary Committee plays a critical role in:", "options": ["Writing tax legislation", "Reviewing and holding hearings on judicial nominations", "Overseeing the military", "Managing elections"], "answer": "B", "explanation": "Judicial nominees must pass through the committee before a full Senate vote."},
    {"id": 301, "unit": "Unit 3", "unitName": "Civil Liberties and Civil Rights", "concept": "Regents of UC v. Bakke", "question": "In Regents of the University of California v. Bakke (1978), the Court ruled that:", "options": ["Racial quotas in university admissions are constitutional", "Affirmative action is entirely illegal", "Race can be a factor in admissions but rigid quotas are unconstitutional", "Only test scores should determine admission"], "answer": "C", "explanation": "Bakke established that race-conscious admissions are permissible but quotas are not."},
    {"id": 302, "unit": "Unit 4", "unitName": "American Political Ideologies and Beliefs", "concept": "Education and Ideology", "question": "Research shows that higher levels of education are associated with:", "options": ["Always voting Republican", "More liberal views on social issues but varied views on economic issues", "Always voting Democratic", "No change in political views"], "answer": "B", "explanation": "Education's effect on political views varies by issue area."},
    {"id": 303, "unit": "Unit 5", "unitName": "Political Participation", "concept": "Voter Mobilization Tactics (Stimulus)", "question": "A study shows that personalized text messages reminding voters of their polling location increased turnout by 3%. This demonstrates the effectiveness of:", "options": ["Negative campaigning", "Ignoring voter outreach", "Traditional mail campaigns", "Targeted voter mobilization efforts using technology"], "answer": "D", "explanation": "Modern campaigns use data-driven outreach methods to boost participation."},
    {"id": 304, "unit": "Unit 1", "unitName": "Foundations of American Democracy", "concept": "Separation of Powers Purpose", "question": "The purpose of separating powers among three branches is to:", "options": ["Make government more efficient", "Give the president supreme authority", "Prevent any one branch from becoming too powerful", "Eliminate the need for elections"], "answer": "C", "explanation": "Separation of powers distributes authority to prevent tyranny."},
    {"id": 305, "unit": "Unit 2", "unitName": "Interactions Among Branches", "concept": "Rule of Four", "question": "The 'Rule of Four' at the Supreme Court means:", "options": ["Four branches of government exist", "Four justices must agree to hear a case for certiorari to be granted", "Cases need four hearings", "Four amendments apply"], "answer": "B", "explanation": "At least four justices must vote to accept a case for the Court to grant review."},
    {"id": 306, "unit": "Unit 2", "unitName": "Interactions Among Branches", "concept": "Amicus Curiae", "question": "An amicus curiae brief is filed by:", "options": ["The defendant only", "The prosecution only", "A third party not directly involved in the case who has an interest in the outcome", "The jury"], "answer": "C", "explanation": "Interest groups and other parties file amicus briefs to influence court decisions."},
    {"id": 307, "unit": "Unit 3", "unitName": "Civil Liberties and Civil Rights", "concept": "Habeas Corpus", "question": "A writ of habeas corpus protects against:", "options": ["Unreasonable searches", "Unlawful detention by requiring authorities to justify holding a person", "Self-incrimination", "Excessive bail"], "answer": "B", "explanation": "Habeas corpus ensures that no one is imprisoned without legal cause."},
    {"id": 308, "unit": "Unit 3", "unitName": "Civil Liberties and Civil Rights", "concept": "Equal Rights Amendment", "question": "The Equal Rights Amendment was proposed but never ratified. It would have:", "options": ["Abolished the Electoral College", "Lowered the voting age to 16", "Guaranteed equal rights regardless of sex", "Established term limits for Congress"], "answer": "C", "explanation": "The ERA fell short of the required state ratifications before its deadline."},
    {"id": 309, "unit": "Unit 4", "unitName": "American Political Ideologies and Beliefs", "concept": "Religious Right", "question": "The Religious Right movement in American politics primarily supports:", "options": ["Social conservative policies aligned with evangelical Christian values", "Separation of church and state", "Liberal economic policy", "Reduced military spending"], "answer": "A", "explanation": "The Religious Right has been a powerful force within the Republican Party since the 1980s."},
    {"id": 310, "unit": "Unit 4", "unitName": "American Political Ideologies and Beliefs", "concept": "Blue Dog Democrats", "question": "Blue Dog Democrats are typically:", "options": ["Very liberal", "Socialists", "Identical to progressive Democrats", "Moderate to conservative Democrats often from competitive districts"], "answer": "D", "explanation": "Blue Dogs are centrist Democrats who often break with their party on fiscal or social issues."},
    {"id": 311, "unit": "Unit 5", "unitName": "Political Participation", "concept": "Voter Age and Turnout", "question": "Which age group consistently has the LOWEST voter turnout?", "options": ["18–29 year olds", "30–44 year olds", "45–64 year olds", "65 and older"], "answer": "A", "explanation": "Young voters have historically had the lowest participation rates."},
    {"id": 312, "unit": "Unit 5", "unitName": "Political Participation", "concept": "Partisan Primary Effects", "question": "Critics argue that closed primaries can lead to:", "options": ["More moderate candidates", "Higher turnout", "More ideologically extreme nominees because only party loyalists vote", "Fewer candidates running"], "answer": "C", "explanation": "When only strong partisans vote, candidates may appeal to the base rather than the center."},
    {"id": 313, "unit": "Unit 1", "unitName": "Foundations of American Democracy", "concept": "Social Contract Details", "question": "In social contract theory, people agree to give up some freedoms in exchange for:", "options": ["Absolute liberty", "No government at all", "Corporate profits", "Government protection and order"], "answer": "D", "explanation": "The social contract involves trading some natural freedom for security and organized governance."},
    {"id": 314, "unit": "Unit 2", "unitName": "Interactions Among Branches", "concept": "Congressional Budget Process", "question": "The federal budget process begins when:", "options": ["Congress writes its own budget from scratch", "The Supreme Court allocates funds", "State governors set the budget", "The president submits a budget proposal to Congress"], "answer": "D", "explanation": "The president's budget proposal starts the process, but Congress has the power of the purse."},
    {"id": 315, "unit": "Unit 3", "unitName": "Civil Liberties and Civil Rights", "concept": "Gonzalez v. Carhart", "question": "In Gonzalez v. Carhart (2007), the Court upheld:", "options": ["Unrestricted abortion rights", "A federal ban on a specific late-term abortion procedure", "Complete state control over abortion", "The original Roe v. Wade framework"], "answer": "B", "explanation": "The ruling upheld the Partial-Birth Abortion Ban Act."},
    {"id": 316, "unit": "Unit 4", "unitName": "American Political Ideologies and Beliefs", "concept": "Moderate Voters", "question": "Moderate voters are important in elections because they:", "options": ["Always vote for incumbents", "Never vote", "Only vote in midterms", "Can swing elections since they are not firmly committed to either party"], "answer": "D", "explanation": "Moderates are often the decisive voters in competitive elections."},
    {"id": 317, "unit": "Unit 5", "unitName": "Political Participation", "concept": "Super Tuesday", "question": "Super Tuesday is significant because:", "options": ["It is the final day of primary elections", "It is a federal holiday", "Only superdelegates vote on this day", "Many states hold primaries on the same day, often determining the nominee"], "answer": "D", "explanation": "The large number of simultaneous primaries can effectively decide the nomination."},
    {"id": 318, "unit": "Unit 1", "unitName": "Foundations of American Democracy", "concept": "Popular Sovereignty", "question": "Popular sovereignty means that government power comes from:", "options": ["The consent of the governed", "The military", "The Constitution alone", "Religious authority"], "answer": "A", "explanation": "Popular sovereignty holds that the people are the ultimate source of government authority."},
    {"id": 319, "unit": "Unit 1", "unitName": "Foundations of American Democracy", "concept": "Limited Government", "question": "The concept of limited government is best described as:", "options": ["Government has no power", "Only the president has power", "Government power is restricted by law", "States have no authority"], "answer": "C", "explanation": "Limited government means the government can only exercise powers granted to it by the people through law."},
    {"id": 320, "unit": "Unit 1", "unitName": "Foundations of American Democracy", "concept": "Rule of Law", "question": "The rule of law means that:", "options": ["The president is above the law", "Judges make all laws", "Only Congress must follow the law", "Laws apply equally to all, including government officials"], "answer": "D", "explanation": "The rule of law ensures that no person or institution is above the law."},
    {"id": 321, "unit": "Unit 1", "unitName": "Foundations of American Democracy", "concept": "Natural Rights", "question": "According to John Locke, natural rights include:", "options": ["Life, liberty, and the pursuit of happiness", "Speech, press, and assembly", "Voting, petition, and protest", "Life, liberty, and property"], "answer": "D", "explanation": "Locke identified life, liberty, and property as fundamental natural rights."},
    {"id": 322, "unit": "Unit 1", "unitName": "Foundations of American Democracy", "concept": "Social Contract", "question": "The social contract theory suggests that:", "options": ["People agree to give up some freedom in exchange for protection", "Government is divinely ordained", "The strongest should rule", "Democracy is the only legitimate government"], "answer": "A", "explanation": "Social contract theory holds that government legitimacy comes from the consent of the governed."},
    {"id": 323, "unit": "Unit 1", "unitName": "Foundations of American Democracy", "concept": "Participatory Democracy", "question": "Participatory democracy emphasizes:", "options": ["Elite decision-making", "Military rule", "Broad citizen involvement in political processes", "Corporate governance"], "answer": "C", "explanation": "Participatory democracy stresses active citizen engagement in government decisions."},
    {"id": 324, "unit": "Unit 1", "unitName": "Foundations of American Democracy", "concept": "Pluralist Democracy", "question": "Pluralist democracy theory argues that:", "options": ["One group dominates politics", "Power is distributed among many competing groups", "Only elites make decisions", "Direct democracy is best"], "answer": "B", "explanation": "Pluralism holds that multiple groups compete for influence, preventing any single group from dominating."},
    {"id": 325, "unit": "Unit 1", "unitName": "Foundations of American Democracy", "concept": "Elite Democracy", "question": "Elite democracy theory holds that:", "options": ["All citizens participate equally", "Direct voting on all issues is best", "Political parties are unnecessary", "A small group of wealthy and well-educated citizens lead government"], "answer": "D", "explanation": "Elite theory suggests that a small minority of wealthy, educated people make most political decisions."},
    {"id": 326, "unit": "Unit 1", "unitName": "Foundations of American Democracy", "concept": "Ratification Debates", "question": "The main debate during ratification of the Constitution was between:", "options": ["Federalists and Anti-Federalists", "Democrats and Republicans", "Northern and Southern states only", "Congress and the president"], "answer": "A", "explanation": "Federalists supported the Constitution while Anti-Federalists opposed it without a Bill of Rights."},
    {"id": 327, "unit": "Unit 1", "unitName": "Foundations of American Democracy", "concept": "Bill of Rights Purpose", "question": "The Bill of Rights was added to the Constitution primarily to:", "options": ["Create the federal court system", "Establish the Electoral College", "Protect individual liberties from government overreach", "Define presidential powers"], "answer": "C", "explanation": "The first ten amendments protect fundamental rights and were added to address Anti-Federalist concerns."},
    {"id": 328, "unit": "Unit 1", "unitName": "Foundations of American Democracy", "concept": "Federalist No. 70", "question": "In Federalist No. 70, Alexander Hamilton argues for:", "options": ["A weak executive", "Congressional supremacy", "Direct democracy", "A strong, unitary executive"], "answer": "D", "explanation": "Hamilton argued that 'energy in the executive' requires a single president with decisive authority."},
    {"id": 329, "unit": "Unit 1", "unitName": "Foundations of American Democracy", "concept": "Cooperative Federalism", "question": "Cooperative federalism is characterized by:", "options": ["Strict separation of state and federal powers", "Complete federal dominance", "National and state governments working together on shared programs", "States acting independently of the federal government"], "answer": "C", "explanation": "Cooperative federalism involves collaboration between levels of government, often called 'marble-cake' federalism."},
    {"id": 330, "unit": "Unit 1", "unitName": "Foundations of American Democracy", "concept": "Dual Federalism", "question": "Dual federalism is best described as:", "options": ["Overlapping responsibilities between state and federal government", "Complete federal control", "States ignoring federal law", "A clear division of authority between state and federal governments"], "answer": "D", "explanation": "Dual federalism, or 'layer-cake' federalism, maintains distinct spheres of authority for each level."},
    {"id": 331, "unit": "Unit 1", "unitName": "Foundations of American Democracy", "concept": "Fiscal Federalism", "question": "Fiscal federalism refers to:", "options": ["The system of federal grants and funding to state and local governments", "State taxation only", "The national debt", "Congressional budget process"], "answer": "A", "explanation": "Fiscal federalism describes how the federal government uses grants to influence state policy."},
    {"id": 332, "unit": "Unit 1", "unitName": "Foundations of American Democracy", "concept": "Block Grants", "question": "Block grants differ from categorical grants because they:", "options": ["Give states broad discretion in how to spend the funds", "Must be used for specific purposes", "Come from state governments", "Require no matching funds"], "answer": "A", "explanation": "Block grants provide funds with fewer restrictions, giving states flexibility in spending."},
    {"id": 333, "unit": "Unit 1", "unitName": "Foundations of American Democracy", "concept": "Unfunded Mandates", "question": "Unfunded mandates are controversial because they:", "options": ["Require states to implement federal policies without federal funding", "Give states too much money", "Allow states to ignore federal law", "Only apply to large states"], "answer": "A", "explanation": "Unfunded mandates impose costs on states without providing financial support."},
    {"id": 334, "unit": "Unit 1", "unitName": "Foundations of American Democracy", "concept": "10th Amendment", "question": "The 10th Amendment reserves powers to:", "options": ["The federal government", "The president", "The states or the people", "The Supreme Court"], "answer": "C", "explanation": "The 10th Amendment states that powers not delegated to the federal government are reserved to the states or the people."},
    {"id": 335, "unit": "Unit 1", "unitName": "Foundations of American Democracy", "concept": "Privileges and Immunities", "question": "The Privileges and Immunities Clause requires states to:", "options": ["Give their citizens extra rights", "Treat citizens of other states fairly and equally", "Allow free travel only", "Share tax revenue"], "answer": "B", "explanation": "States cannot discriminate against citizens of other states regarding fundamental rights."},
    {"id": 336, "unit": "Unit 1", "unitName": "Foundations of American Democracy", "concept": "Devolution", "question": "Devolution refers to:", "options": ["Increasing federal power", "Eliminating state governments", "Judicial activism", "Transferring power from the federal government to state governments"], "answer": "D", "explanation": "Devolution is the process of shifting responsibilities from the federal level to the states."},
    {"id": 337, "unit": "Unit 1", "unitName": "Foundations of American Democracy", "concept": "Categorical Grants", "question": "Categorical grants require state governments to:", "options": ["Use funds for specific, federally defined purposes", "Spend money however they choose", "Match no funding", "Apply through their governors only"], "answer": "A", "explanation": "Categorical grants come with strict conditions on how the money must be spent."},
    {"id": 338, "unit": "Unit 1", "unitName": "Foundations of American Democracy", "concept": "Marbury v. Madison", "question": "Marbury v. Madison is significant because it established:", "options": ["The right to vote", "Presidential term limits", "The power of judicial review", "Congressional oversight"], "answer": "C", "explanation": "Chief Justice Marshall's ruling established the Supreme Court's authority to declare laws unconstitutional."},
    {"id": 339, "unit": "Unit 1", "unitName": "Foundations of American Democracy", "concept": "Necessary and Proper Clause Impact", "question": "The Necessary and Proper Clause has been used to:", "options": ["Limit federal power", "Give states more autonomy", "Reduce presidential authority", "Expand Congress's authority beyond enumerated powers"], "answer": "D", "explanation": "The Elastic Clause allows Congress to pass laws beyond those specifically listed in Article I."},
    {"id": 340, "unit": "Unit 1", "unitName": "Foundations of American Democracy", "concept": "Article V", "question": "Article V of the Constitution describes the process for:", "options": ["Electing the president", "Amending the Constitution", "Creating federal courts", "Declaring war"], "answer": "B", "explanation": "Article V outlines two methods for proposing and ratifying constitutional amendments."},
    {"id": 341, "unit": "Unit 1", "unitName": "Foundations of American Democracy", "concept": "Separation of Powers Purpose", "question": "The primary purpose of separation of powers is to:", "options": ["Make government more efficient", "Give the president more authority", "Allow states to override federal law", "Prevent the concentration of power in any single branch"], "answer": "D", "explanation": "Dividing power among branches prevents tyranny by ensuring no single branch dominates."},
    {"id": 342, "unit": "Unit 1", "unitName": "Foundations of American Democracy", "concept": "Federalist No. 78", "question": "In Federalist No. 78, Hamilton argues that the judiciary is the 'least dangerous branch' because it:", "options": ["Controls the military", "Has neither the power of the purse nor the sword", "Is elected by the people", "Can override Congress"], "answer": "B", "explanation": "Hamilton noted that courts depend on the executive to enforce decisions and Congress for funding."},
    {"id": 343, "unit": "Unit 1", "unitName": "Foundations of American Democracy", "concept": "Consent of the Governed", "question": "The idea of 'consent of the governed' is central to:", "options": ["Democratic legitimacy and the Declaration of Independence", "Authoritarian government", "Monarchy", "Theocracy"], "answer": "A", "explanation": "The Declaration states that governments derive their just powers from the consent of the governed."},
    {"id": 344, "unit": "Unit 1", "unitName": "Foundations of American Democracy", "concept": "Republican Government", "question": "The Founders chose a republican form of government because they:", "options": ["Wanted direct democracy", "Believed elected representatives would filter popular passions", "Opposed all forms of voting", "Wanted monarchy"], "answer": "B", "explanation": "The Founders feared pure democracy and chose representative government to temper majority factions."},
    {"id": 345, "unit": "Unit 1", "unitName": "Foundations of American Democracy", "concept": "Interstate Compact Clause", "question": "The Interstate Compact Clause requires that agreements between states:", "options": ["Never occur", "Be approved by the president only", "Be ratified by all 50 states", "Receive congressional approval"], "answer": "D", "explanation": "States may enter into compacts with each other, but significant agreements require congressional consent."},
    {"id": 346, "unit": "Unit 1", "unitName": "Foundations of American Democracy", "concept": "Extradition Clause", "question": "The Extradition Clause requires that:", "options": ["States can refuse to return fugitives", "Only the federal government handles fugitives", "A state must return a person accused of a crime to the state where the crime occurred", "International treaties govern all extraditions"], "answer": "C", "explanation": "Article IV requires states to return fugitives to the state where they are charged."},
    {"id": 347, "unit": "Unit 1", "unitName": "Foundations of American Democracy", "concept": "Shays Rebellion", "question": "Shays' Rebellion demonstrated the need for:", "options": ["Weaker federal government", "A stronger national government that could maintain order", "More state sovereignty", "Abolishing the military"], "answer": "B", "explanation": "The uprising of indebted farmers exposed the weakness of the Articles of Confederation."},
    {"id": 348, "unit": "Unit 1", "unitName": "Foundations of American Democracy", "concept": "Virginia Plan vs New Jersey Plan", "question": "The Virginia Plan proposed representation based on:", "options": ["Equal representation for all states", "Geographic area", "State population size", "Wealth of each state"], "answer": "C", "explanation": "Larger states favored the Virginia Plan's population-based representation in both chambers."},
    {"id": 349, "unit": "Unit 1", "unitName": "Foundations of American Democracy", "concept": "Electoral College Purpose", "question": "The Electoral College was created as a compromise between:", "options": ["Election by Congress and election by popular vote", "Northern and Southern states", "Large and small states only", "Federalists and Anti-Federalists only"], "answer": "A", "explanation": "The Founders designed the Electoral College as a middle ground between congressional and popular election."},
    {"id": 350, "unit": "Unit 1", "unitName": "Foundations of American Democracy", "concept": "Three-Fifths Compromise", "question": "The Three-Fifths Compromise addressed:", "options": ["How enslaved persons would be counted for representation and taxation", "How states would be represented in the Senate", "Tariffs on imported goods", "The slave trade"], "answer": "A", "explanation": "Enslaved individuals were counted as three-fifths of a person for apportionment purposes."},
    {"id": 351, "unit": "Unit 1", "unitName": "Foundations of American Democracy", "concept": "Implied Powers", "question": "Implied powers of Congress are those that:", "options": ["Are explicitly listed in the Constitution", "Belong only to the states", "Are reasonably inferred from enumerated powers through the Necessary and Proper Clause", "Are granted by the president"], "answer": "C", "explanation": "Implied powers allow Congress flexibility to address issues not explicitly covered in the Constitution."},
    {"id": 352, "unit": "Unit 1", "unitName": "Foundations of American Democracy", "concept": "Mandates in Federalism", "question": "Federal mandates can affect state policy by:", "options": ["Requiring states to comply with federal standards as a condition of receiving funds", "Having no impact on states", "Letting states completely ignore federal law", "Only applying to border states"], "answer": "A", "explanation": "The federal government uses mandates and conditions on grants to influence state behavior."},
    {"id": 353, "unit": "Unit 1", "unitName": "Foundations of American Democracy", "concept": "Supremacy Clause Application", "question": "When a state law conflicts with a valid federal law, the Supremacy Clause dictates that:", "options": ["The federal law prevails", "The state law prevails", "Both are void", "The Supreme Court decides case-by-case"], "answer": "A", "explanation": "Article VI establishes that federal law is the supreme law of the land when there is a conflict."},
    {"id": 354, "unit": "Unit 2", "unitName": "Interactions Among Branches", "concept": "Executive Agreements", "question": "Executive agreements differ from treaties because they:", "options": ["Require Senate approval", "Must be approved by the House", "Do not require Senate ratification", "Cannot involve foreign nations"], "answer": "C", "explanation": "Presidents use executive agreements to make deals with foreign leaders without Senate consent."},
    {"id": 355, "unit": "Unit 2", "unitName": "Interactions Among Branches", "concept": "Judicial Activism", "question": "Judicial activism occurs when judges:", "options": ["Strictly follow precedent", "Refuse to hear cases", "Interpret the Constitution broadly to shape social policy", "Defer to the legislature on all matters"], "answer": "C", "explanation": "Activist judges are willing to strike down laws and issue broad rulings on policy questions."},
    {"id": 356, "unit": "Unit 2", "unitName": "Interactions Among Branches", "concept": "Judicial Restraint", "question": "Judicial restraint is the philosophy that courts should:", "options": ["Actively create new rights", "Always side with the government", "Ignore precedent", "Defer to elected branches and avoid overturning laws unless clearly unconstitutional"], "answer": "D", "explanation": "Proponents of restraint argue that courts should respect the democratic process."},
    {"id": 357, "unit": "Unit 2", "unitName": "Interactions Among Branches", "concept": "Rule of Four", "question": "The 'Rule of Four' in the Supreme Court refers to:", "options": ["Four justices must agree to hear a case for certiorari to be granted", "Four justices must recuse themselves", "A case must have four appeals", "Four amicus briefs are required"], "answer": "A", "explanation": "At least four of the nine justices must vote to grant certiorari for the Court to hear a case."},
    {"id": 358, "unit": "Unit 2", "unitName": "Interactions Among Branches", "concept": "Amicus Curiae", "question": "An amicus curiae brief is filed by:", "options": ["The defendant only", "The judge", "A non-party with an interest in the case to provide additional perspective", "The jury"], "answer": "C", "explanation": "Amicus ('friend of the court') briefs allow outside groups to influence the Court's reasoning."},
    {"id": 359, "unit": "Unit 2", "unitName": "Interactions Among Branches", "concept": "Majority Opinion", "question": "A majority opinion is significant because it:", "options": ["Has no legal effect", "Only applies to the specific parties", "Is written by the losing side", "Establishes binding legal precedent"], "answer": "D", "explanation": "The majority opinion represents the Court's official ruling and becomes the law of the land."},
    {"id": 360, "unit": "Unit 2", "unitName": "Interactions Among Branches", "concept": "Dissenting Opinion", "question": "A dissenting opinion in a Supreme Court case:", "options": ["Becomes law", "Is always unanimous", "Must be signed by all justices", "Is written by justices who disagree with the majority and may influence future rulings"], "answer": "D", "explanation": "Dissents can lay the groundwork for future cases to overturn the majority's precedent."},
    {"id": 361, "unit": "Unit 2", "unitName": "Interactions Among Branches", "concept": "Concurring Opinion", "question": "A concurring opinion agrees with the majority ruling but:", "options": ["For the same reasons", "Disagrees with the outcome", "For different legal reasoning", "Is written by the losing party"], "answer": "C", "explanation": "Concurrences allow justices to express alternative rationales for reaching the same conclusion."},
    {"id": 362, "unit": "Unit 2", "unitName": "Interactions Among Branches", "concept": "Pocket Veto", "question": "A pocket veto occurs when:", "options": ["The president vetoes a bill publicly", "Congress overrides a veto", "The vice president vetoes a bill", "The president takes no action on a bill and Congress adjourns within 10 days"], "answer": "D", "explanation": "If the president does not sign a bill and Congress adjourns during the 10-day window, the bill dies."},
    {"id": 363, "unit": "Unit 2", "unitName": "Interactions Among Branches", "concept": "Line Item Veto", "question": "The Supreme Court struck down the line-item veto because it:", "options": ["Was too expensive", "Was never used", "Violated the Presentment Clause by allowing the president to amend legislation", "Gave Congress too much power"], "answer": "C", "explanation": "In Clinton v. City of New York (1998), the Court ruled the line-item veto unconstitutional."},
    {"id": 364, "unit": "Unit 2", "unitName": "Interactions Among Branches", "concept": "Discharge Petition", "question": "A discharge petition in the House is used to:", "options": ["Fire a committee chair", "Override a veto", "Force a bill out of committee to the full floor for a vote", "Impeach a president"], "answer": "C", "explanation": "A majority (218) of House members must sign a discharge petition to bring a bill to the floor."},
    {"id": 365, "unit": "Unit 2", "unitName": "Interactions Among Branches", "concept": "Riders and Amendments", "question": "A rider in legislation is:", "options": ["An unrelated amendment attached to a bill to gain passage", "A mandatory provision", "A veto by the president", "A filibuster tactic"], "answer": "A", "explanation": "Riders are provisions added to must-pass bills that might not pass on their own merits."},
    {"id": 366, "unit": "Unit 2", "unitName": "Interactions Among Branches", "concept": "Government Corporations", "question": "Government corporations like the U.S. Postal Service differ from agencies because they:", "options": ["Have no employees", "Operate more like businesses and can charge for services", "Are completely private", "Report to state governments"], "answer": "B", "explanation": "Government corporations provide services that could be offered by the private sector."},
    {"id": 367, "unit": "Unit 2", "unitName": "Interactions Among Branches", "concept": "Independent Executive Agencies", "question": "Independent executive agencies report to:", "options": ["Congress directly", "The president but are not part of cabinet departments", "The Supreme Court", "State governors"], "answer": "B", "explanation": "Agencies like NASA and the EPA operate independently of cabinet departments but answer to the president."},
    {"id": 368, "unit": "Unit 2", "unitName": "Interactions Among Branches", "concept": "Iron Triangle Dynamics", "question": "An iron triangle creates policy through the relationship between:", "options": ["Three branches of government", "Three political parties", "A congressional committee, a bureaucratic agency, and an interest group", "Federal, state, and local courts"], "answer": "C", "explanation": "These three actors form a mutually beneficial relationship to influence policy in a specific area."},
    {"id": 369, "unit": "Unit 2", "unitName": "Interactions Among Branches", "concept": "Issue Networks", "question": "Issue networks differ from iron triangles because they:", "options": ["Are permanent and closed", "Include a broader, more fluid group of participants on a policy issue", "Have fewer members", "Only involve the president"], "answer": "B", "explanation": "Issue networks are more open and include experts, media, and various interest groups."},
    {"id": 370, "unit": "Unit 2", "unitName": "Interactions Among Branches", "concept": "Bureaucratic Discretion", "question": "Bureaucratic discretion refers to:", "options": ["Strict rule-following with no flexibility", "The president's veto power", "The latitude agencies have in interpreting and implementing laws", "Congressional oversight"], "answer": "C", "explanation": "Agencies often must interpret vague legislation, giving unelected officials significant policy influence."},
    {"id": 371, "unit": "Unit 2", "unitName": "Interactions Among Branches", "concept": "Congressional Budget Process", "question": "The federal budget process begins when:", "options": ["Congress writes its own budget", "The Supreme Court sets spending limits", "State governors submit requests", "The president submits a budget proposal to Congress"], "answer": "D", "explanation": "The president's budget proposal is the starting point, though Congress has the final say on spending."},
    {"id": 372, "unit": "Unit 2", "unitName": "Interactions Among Branches", "concept": "Confirmation Hearings", "question": "Senate confirmation hearings for judicial nominees have become more contentious because:", "options": ["The Constitution requires it", "Nominees are elected by the public", "The House also confirms judges", "Federal judges serve life terms, making appointments high-stakes ideological battles"], "answer": "D", "explanation": "Lifetime appointments mean each justice can shape law for decades, intensifying partisan conflict."},
    {"id": 373, "unit": "Unit 2", "unitName": "Interactions Among Branches", "concept": "Executive Privilege", "question": "Executive privilege is the president's claimed right to:", "options": ["Withhold information from Congress and the courts to protect national security", "Ignore Supreme Court rulings", "Pardon any crime", "Declare war without Congress"], "answer": "A", "explanation": "While not explicitly in the Constitution, courts have recognized limited executive privilege."},
    {"id": 374, "unit": "Unit 2", "unitName": "Interactions Among Branches", "concept": "Recess Appointments", "question": "Recess appointments allow the president to:", "options": ["Temporarily fill vacancies when the Senate is in recess without confirmation", "Fire members of Congress", "Adjourn Congress", "Override a veto"], "answer": "A", "explanation": "Recess appointments bypass Senate confirmation but expire at the end of the next Senate session."},
    {"id": 375, "unit": "Unit 2", "unitName": "Interactions Among Branches", "concept": "Delegated Legislation", "question": "When Congress delegates rulemaking authority to agencies, this is called:", "options": ["Judicial review", "Impeachment", "Cloture", "Delegated or administrative rulemaking"], "answer": "D", "explanation": "Congress often passes broad statutes and lets agencies fill in the details through regulations."},
    {"id": 376, "unit": "Unit 2", "unitName": "Interactions Among Branches", "concept": "Whistleblower Protections", "question": "Whistleblower protections are important because they:", "options": ["Punish government employees", "Allow agencies to ignore Congress", "Encourage reporting of government waste and abuse by protecting employees from retaliation", "Eliminate bureaucratic discretion"], "answer": "C", "explanation": "These protections help ensure government accountability by shielding those who report wrongdoing."},
    {"id": 377, "unit": "Unit 2", "unitName": "Interactions Among Branches", "concept": "Power of Impeachment", "question": "The standard for impeachment is:", "options": ["High crimes and misdemeanors, as determined by Congress", "Criminal conviction", "Losing a popular vote", "Unpopularity in polls"], "answer": "A", "explanation": "The Constitution gives Congress broad discretion to define impeachable offenses."},
    {"id": 378, "unit": "Unit 2", "unitName": "Interactions Among Branches", "concept": "Treaty Power", "question": "The president negotiates treaties, but they must be ratified by:", "options": ["A simple majority of the House", "A two-thirds vote of the Senate", "A popular referendum", "The Supreme Court"], "answer": "B", "explanation": "Article II requires a two-thirds Senate supermajority to ratify treaties."},
    {"id": 379, "unit": "Unit 2", "unitName": "Interactions Among Branches", "concept": "Senatorial Courtesy", "question": "Senatorial courtesy is the practice of:", "options": ["Always confirming nominees", "The president consulting with home-state senators before nominating federal judges", "Senators never opposing each other", "Automatic approval of all appointments"], "answer": "B", "explanation": "This informal practice gives senators influence over judicial appointments in their states."},
    {"id": 380, "unit": "Unit 2", "unitName": "Interactions Among Branches", "concept": "Holds in the Senate", "question": "A Senate hold allows a single senator to:", "options": ["Pass a bill immediately", "Delay or block consideration of a bill or nomination", "Override the president", "Dismiss a committee chair"], "answer": "B", "explanation": "Holds are an informal practice that can be used to leverage negotiations or block action."},
    {"id": 381, "unit": "Unit 2", "unitName": "Interactions Among Branches", "concept": "Omnibus Legislation", "question": "Omnibus bills are significant because they:", "options": ["Address only one narrow issue", "Combine many provisions into a single large bill, making them harder to oppose", "Are always vetoed", "Only deal with the budget"], "answer": "B", "explanation": "Omnibus legislation bundles multiple policies together, often as a strategy to pass controversial provisions."},
    {"id": 382, "unit": "Unit 2", "unitName": "Interactions Among Branches", "concept": "Continuing Resolution", "question": "When Congress cannot pass a budget on time, it may pass a continuing resolution which:", "options": ["Shuts down the government", "Increases all spending", "Funds the government at current levels temporarily", "Eliminates the national debt"], "answer": "C", "explanation": "Continuing resolutions maintain existing funding levels while Congress negotiates a new budget."},
    {"id": 383, "unit": "Unit 2", "unitName": "Interactions Among Branches", "concept": "Government Shutdown", "question": "A government shutdown occurs when:", "options": ["The president resigns", "Congress fails to pass appropriations bills or a continuing resolution", "The Supreme Court orders it", "A natural disaster strikes"], "answer": "B", "explanation": "Without funding legislation, non-essential government operations must cease."},
    {"id": 384, "unit": "Unit 2", "unitName": "Interactions Among Branches", "concept": "Presentment Clause", "question": "The Presentment Clause requires that:", "options": ["Every bill passed by Congress must be presented to the president for signature or veto", "The president present a State of the Union address", "Judges present opinions to Congress", "Citizens present petitions"], "answer": "A", "explanation": "This clause ensures the president has the opportunity to approve or reject legislation."},
    {"id": 385, "unit": "Unit 2", "unitName": "Interactions Among Branches", "concept": "22nd Amendment", "question": "The 22nd Amendment limits the president to:", "options": ["One term", "Three terms", "Two terms in office", "Unlimited terms"], "answer": "C", "explanation": "Ratified in 1951 after FDR served four terms, it limits presidents to two elected terms."},
    {"id": 386, "unit": "Unit 2", "unitName": "Interactions Among Branches", "concept": "25th Amendment", "question": "The 25th Amendment addresses:", "options": ["Voting rights", "Freedom of speech", "Presidential succession and disability", "States' rights"], "answer": "C", "explanation": "It clarifies the process when a president is unable to serve and how vacancies are filled."},
    {"id": 387, "unit": "Unit 2", "unitName": "Interactions Among Branches", "concept": "Bureaucratic Accountability", "question": "Congress checks bureaucratic power through all of the following EXCEPT:", "options": ["Hearings and investigations", "Controlling agency budgets", "Rewriting enabling legislation", "Issuing executive orders to agencies"], "answer": "D", "explanation": "Executive orders are a presidential tool; Congress uses oversight hearings, budgets, and legislation."},
    {"id": 388, "unit": "Unit 3", "unitName": "Civil Liberties and Civil Rights", "concept": "Free Exercise Clause", "question": "The Free Exercise Clause protects:", "options": ["Government establishment of religion", "The right of individuals to practice their religion freely", "Only Christian worship", "Prayer in public schools"], "answer": "B", "explanation": "The First Amendment protects religious practice, though the government may impose neutral, generally applicable laws."},
    {"id": 389, "unit": "Unit 3", "unitName": "Civil Liberties and Civil Rights", "concept": "Lemon Test", "question": "The Lemon test, from Lemon v. Kurtzman, evaluates whether a government action:", "options": ["Violates the Establishment Clause by lacking a secular purpose or excessively entangling government with religion", "Violates free speech", "Is a valid tax", "Protects property rights"], "answer": "A", "explanation": "The three-pronged test assesses secular purpose, primary effect, and excessive entanglement."},
    {"id": 390, "unit": "Unit 3", "unitName": "Civil Liberties and Civil Rights", "concept": "Symbolic Speech", "question": "In Texas v. Johnson, the Supreme Court ruled that flag burning is:", "options": ["Always illegal", "Only legal in wartime", "A form of treason", "Protected symbolic speech under the First Amendment"], "answer": "D", "explanation": "The Court held that flag burning is expressive conduct protected by the First Amendment."},
    {"id": 391, "unit": "Unit 3", "unitName": "Civil Liberties and Civil Rights", "concept": "Prior Restraint", "question": "Prior restraint refers to government action that:", "options": ["Punishes speech after the fact", "Protects speech", "Prevents expression before it occurs, which is presumptively unconstitutional", "Encourages more speech"], "answer": "C", "explanation": "Near v. Minnesota and the Pentagon Papers case established strong protections against prior restraint."},
    {"id": 392, "unit": "Unit 3", "unitName": "Civil Liberties and Civil Rights", "concept": "Obscenity Standard", "question": "The Miller test determines whether material is obscene based on:", "options": ["Any offensiveness", "Government opinion", "Popular vote", "Community standards, whether it appeals to prurient interest, and whether it lacks serious value"], "answer": "D", "explanation": "Miller v. California established a three-part test for obscenity, which is not protected speech."},
    {"id": 393, "unit": "Unit 3", "unitName": "Civil Liberties and Civil Rights", "concept": "Commercial Speech", "question": "Commercial speech receives:", "options": ["Some First Amendment protection, but less than political speech", "No protection", "Full protection equal to political speech", "More protection than political speech"], "answer": "A", "explanation": "The government can regulate advertising more than political expression but cannot ban truthful ads."},
    {"id": 394, "unit": "Unit 3", "unitName": "Civil Liberties and Civil Rights", "concept": "Libel and Slander", "question": "Public officials suing for libel must prove:", "options": ["Simple negligence", "Actual malice—that the statement was made with knowledge of its falsity or reckless disregard", "Any inaccuracy", "That they were offended"], "answer": "B", "explanation": "New York Times v. Sullivan set a high bar for public figures to win defamation cases."},
    {"id": 395, "unit": "Unit 3", "unitName": "Civil Liberties and Civil Rights", "concept": "Right to Privacy", "question": "The right to privacy is:", "options": ["Explicitly stated in the Bill of Rights", "Only in the 4th Amendment", "Implied from several amendments including the 1st, 3rd, 4th, 5th, and 14th", "Not recognized by courts"], "answer": "C", "explanation": "Griswold v. Connecticut found a right to privacy in the 'penumbras' of various amendments."},
    {"id": 396, "unit": "Unit 3", "unitName": "Civil Liberties and Civil Rights", "concept": "Exclusionary Rule Origin", "question": "The exclusionary rule was applied to states through:", "options": ["The 5th Amendment directly", "A congressional statute", "Mapp v. Ohio, incorporating the 4th Amendment via the 14th", "Executive order"], "answer": "C", "explanation": "Mapp extended the federal exclusionary rule to state courts through selective incorporation."},
    {"id": 397, "unit": "Unit 3", "unitName": "Civil Liberties and Civil Rights", "concept": "Right to Counsel", "question": "The right to counsel in state criminal cases was established by:", "options": ["Miranda v. Arizona", "Gideon v. Wainwright, which incorporated the 6th Amendment right to an attorney", "Marbury v. Madison", "Brown v. Board"], "answer": "B", "explanation": "Gideon held that states must provide lawyers for defendants who cannot afford them."},
    {"id": 398, "unit": "Unit 3", "unitName": "Civil Liberties and Civil Rights", "concept": "Double Jeopardy", "question": "The protection against double jeopardy means:", "options": ["You can be tried twice for the same crime", "You cannot appeal a conviction", "All charges must be filed at once", "A person cannot be tried twice for the same offense by the same government"], "answer": "D", "explanation": "The 5th Amendment protects against being tried twice, though separate sovereigns (state and federal) may both prosecute."},
    {"id": 399, "unit": "Unit 3", "unitName": "Civil Liberties and Civil Rights", "concept": "Cruel and Unusual Punishment", "question": "The 8th Amendment's prohibition on cruel and unusual punishment has been interpreted to:", "options": ["Allow any punishment", "Apply only to physical punishment", "Never change", "Evolve with society's standards of decency"], "answer": "D", "explanation": "The Court uses 'evolving standards of decency' to determine what punishments are prohibited."},
    {"id": 400, "unit": "Unit 3", "unitName": "Civil Liberties and Civil Rights", "concept": "Death Penalty Jurisprudence", "question": "The Supreme Court has ruled that the death penalty:", "options": ["Is always unconstitutional", "Must be mandatory for murder", "Can be imposed for any felony", "Is constitutional but cannot be applied to juveniles or intellectually disabled defendants"], "answer": "D", "explanation": "Roper v. Simmons banned execution of juveniles; Atkins v. Virginia banned it for the intellectually disabled."},
    {"id": 401, "unit": "Unit 3", "unitName": "Civil Liberties and Civil Rights", "concept": "Strict Scrutiny", "question": "Strict scrutiny is the standard of review used when government action involves:", "options": ["A suspect classification like race or a fundamental right", "Economic regulation", "Traffic laws", "Property taxes"], "answer": "A", "explanation": "Under strict scrutiny, the government must show a compelling interest and the law must be narrowly tailored."},
    {"id": 402, "unit": "Unit 3", "unitName": "Civil Liberties and Civil Rights", "concept": "Intermediate Scrutiny", "question": "Intermediate scrutiny applies to classifications based on:", "options": ["Race", "Wealth", "Age", "Gender, requiring the government to show an important interest"], "answer": "D", "explanation": "Craig v. Boren established intermediate scrutiny for gender-based classifications."},
    {"id": 403, "unit": "Unit 3", "unitName": "Civil Liberties and Civil Rights", "concept": "Rational Basis Test", "question": "The rational basis test requires that a law:", "options": ["Serve a compelling interest", "Be rationally related to a legitimate government interest", "Pass strict scrutiny", "Be approved by voters"], "answer": "B", "explanation": "This is the most deferential standard; most economic and social legislation passes this test."},
    {"id": 404, "unit": "Unit 3", "unitName": "Civil Liberties and Civil Rights", "concept": "Voting Rights Act Provisions", "question": "The Voting Rights Act of 1965 was strengthened by:", "options": ["Eliminating all voting requirements", "Allowing only federal elections", "Requiring federal preclearance of voting changes in jurisdictions with histories of discrimination", "Banning political parties"], "answer": "C", "explanation": "Section 5 preclearance was a key enforcement mechanism until Shelby County v. Holder (2013)."},
    {"id": 405, "unit": "Unit 3", "unitName": "Civil Liberties and Civil Rights", "concept": "Shelby County v. Holder", "question": "In Shelby County v. Holder (2013), the Supreme Court:", "options": ["Struck down the coverage formula used to determine which jurisdictions needed preclearance", "Strengthened the VRA", "Banned all voter ID laws", "Extended voting rights to non-citizens"], "answer": "A", "explanation": "The ruling effectively ended federal preclearance, leaving it to Congress to update the formula."},
    {"id": 406, "unit": "Unit 3", "unitName": "Civil Liberties and Civil Rights", "concept": "Affirmative Action History", "question": "Affirmative action policies were originally designed to:", "options": ["Discriminate against white applicants", "Eliminate all standardized testing", "Guarantee equal outcomes", "Address historical discrimination by promoting opportunities for minorities and women"], "answer": "D", "explanation": "Affirmative action aimed to remedy past discrimination and promote diversity."},
    {"id": 407, "unit": "Unit 3", "unitName": "Civil Liberties and Civil Rights", "concept": "Title IX", "question": "Title IX of the Education Amendments of 1972 prohibits:", "options": ["Racial discrimination in voting", "Age discrimination in employment", "Religious discrimination in housing", "Sex-based discrimination in federally funded educational programs"], "answer": "D", "explanation": "Title IX has been influential in expanding women's athletics and addressing sexual harassment in schools."},
    {"id": 408, "unit": "Unit 3", "unitName": "Civil Liberties and Civil Rights", "concept": "Americans with Disabilities Act", "question": "The Americans with Disabilities Act (1990) requires:", "options": ["Nothing of private businesses", "Reasonable accommodations for people with disabilities in employment and public spaces", "Free healthcare for all disabled persons", "Special voting procedures"], "answer": "B", "explanation": "The ADA prohibits discrimination and mandates accessibility in workplaces and public facilities."},
    {"id": 409, "unit": "Unit 3", "unitName": "Civil Liberties and Civil Rights", "concept": "13th Amendment", "question": "The 13th Amendment accomplished:", "options": ["Women's suffrage", "The abolition of slavery and involuntary servitude", "Lowering the voting age", "Establishing Prohibition"], "answer": "B", "explanation": "Ratified in 1865, the 13th Amendment permanently ended slavery in the United States."},
    {"id": 410, "unit": "Unit 3", "unitName": "Civil Liberties and Civil Rights", "concept": "15th Amendment Purpose", "question": "The 15th Amendment was designed to:", "options": ["Give women the right to vote", "Abolish slavery", "Establish equal protection", "Prohibit denial of voting rights based on race, color, or previous condition of servitude"], "answer": "D", "explanation": "Despite the amendment, Southern states used poll taxes and literacy tests to circumvent it for decades."},
    {"id": 411, "unit": "Unit 3", "unitName": "Civil Liberties and Civil Rights", "concept": "19th Amendment Impact", "question": "The 19th Amendment significantly expanded democracy by:", "options": ["Lowering the voting age", "Abolishing poll taxes", "Granting women the right to vote in all elections", "Establishing direct election of senators"], "answer": "C", "explanation": "Ratified in 1920, it doubled the potential electorate by enfranchising women."},
    {"id": 412, "unit": "Unit 3", "unitName": "Civil Liberties and Civil Rights", "concept": "24th Amendment", "question": "The 24th Amendment eliminated:", "options": ["The Electoral College", "Poll taxes in federal elections", "Term limits", "Slavery"], "answer": "B", "explanation": "Poll taxes had been used primarily in the South to disenfranchise African American voters."},
    {"id": 413, "unit": "Unit 3", "unitName": "Civil Liberties and Civil Rights", "concept": "Civil Rights Movement Strategy", "question": "The civil rights movement achieved its goals primarily through:", "options": ["Nonviolent protest, litigation, and legislative lobbying", "Armed revolution", "Secession threats", "Third-party politics"], "answer": "A", "explanation": "Leaders like MLK Jr. used civil disobedience, legal challenges, and political pressure."},
    {"id": 414, "unit": "Unit 3", "unitName": "Civil Liberties and Civil Rights", "concept": "De Facto vs De Jure Segregation", "question": "De facto segregation differs from de jure segregation in that it:", "options": ["Is mandated by law", "Is unconstitutional", "Exists in practice through housing patterns and social customs, not by law", "Only applies to schools"], "answer": "C", "explanation": "De jure segregation is by law; de facto segregation results from social and economic factors."},
    {"id": 415, "unit": "Unit 3", "unitName": "Civil Liberties and Civil Rights", "concept": "Hate Speech", "question": "In the United States, hate speech is generally:", "options": ["A criminal offense", "Always prohibited", "Regulated by the FCC", "Protected by the First Amendment unless it constitutes a direct threat or incitement"], "answer": "D", "explanation": "Unlike many other democracies, the U.S. broadly protects offensive speech under the First Amendment."},
    {"id": 416, "unit": "Unit 3", "unitName": "Civil Liberties and Civil Rights", "concept": "Student Speech Limits", "question": "In Morse v. Frederick ('Bong Hits 4 Jesus'), the Court ruled that schools can restrict student speech that:", "options": ["Is political", "Criticizes the school", "Is religious", "Promotes illegal drug use"], "answer": "D", "explanation": "The Court held that schools have an interest in deterring drug use among students."},
    {"id": 417, "unit": "Unit 3", "unitName": "Civil Liberties and Civil Rights", "concept": "Second Amendment Scope", "question": "In District of Columbia v. Heller, the Court ruled that the Second Amendment:", "options": ["Only protects militia members", "Allows unlimited gun ownership", "Protects an individual's right to possess firearms for self-defense in the home", "Has been repealed"], "answer": "C", "explanation": "Heller was the first case to definitively establish an individual right to bear arms."},
    {"id": 418, "unit": "Unit 3", "unitName": "Civil Liberties and Civil Rights", "concept": "Eminent Domain", "question": "The 5th Amendment's Takings Clause requires that the government:", "options": ["Provide just compensation when taking private property for public use", "Can take property without limit", "Never take private property", "Only take property during war"], "answer": "A", "explanation": "Kelo v. City of New London expanded the definition of 'public use' to include economic development."},
    {"id": 419, "unit": "Unit 3", "unitName": "Civil Liberties and Civil Rights", "concept": "Right to a Speedy Trial", "question": "The 6th Amendment guarantees the right to a speedy trial, which means:", "options": ["The government cannot hold a defendant indefinitely before trial", "Trials must happen within 24 hours", "All trials last one day", "Defendants cannot request delays"], "answer": "A", "explanation": "This right protects against lengthy pretrial detention and the anxiety of unresolved charges."},
    {"id": 420, "unit": "Unit 3", "unitName": "Civil Liberties and Civil Rights", "concept": "Grand Jury", "question": "The 5th Amendment requires a grand jury for:", "options": ["All criminal cases", "Civil lawsuits", "Traffic violations", "Serious federal criminal charges, to determine if there is enough evidence to indict"], "answer": "D", "explanation": "Grand juries review evidence and decide whether to issue an indictment; they have not been fully incorporated to states."},
    {"id": 421, "unit": "Unit 3", "unitName": "Civil Liberties and Civil Rights", "concept": "Civil Liberties vs Civil Rights", "question": "Civil liberties differ from civil rights in that civil liberties:", "options": ["Protect individuals from government action, while civil rights protect against discrimination", "Are granted by Congress", "Only apply to citizens", "Are not in the Constitution"], "answer": "A", "explanation": "Civil liberties are freedoms FROM government interference; civil rights ensure equal TREATMENT by government."},
    {"id": 422, "unit": "Unit 3", "unitName": "Civil Liberties and Civil Rights", "concept": "Plea Bargaining", "question": "Plea bargaining is significant in the criminal justice system because:", "options": ["It eliminates all trials", "It only applies to misdemeanors", "The vast majority of criminal cases are resolved through negotiated guilty pleas", "Judges are not involved"], "answer": "C", "explanation": "Over 90% of federal criminal cases are resolved through plea bargains rather than trials."},
    {"id": 423, "unit": "Unit 3", "unitName": "Civil Liberties and Civil Rights", "concept": "Substantive Due Process", "question": "Substantive due process protects:", "options": ["Only procedural fairness", "Economic rights only", "The right to a jury trial", "Fundamental rights from government interference, even when proper procedures are followed"], "answer": "D", "explanation": "Substantive due process looks at whether the government has adequate justification for its actions."},
    {"id": 424, "unit": "Unit 4", "unitName": "American Political Ideologies and Beliefs", "concept": "Political Efficacy", "question": "Political efficacy refers to:", "options": ["Government efficiency", "Voter apathy", "Political corruption", "A citizen's belief that their participation in politics matters and can influence government"], "answer": "D", "explanation": "High political efficacy increases voter turnout and civic engagement."},
    {"id": 425, "unit": "Unit 4", "unitName": "American Political Ideologies and Beliefs", "concept": "Exit Polls", "question": "Exit polls are conducted:", "options": ["As voters leave polling places to predict election outcomes", "Before an election", "Only by the government", "During debates"], "answer": "A", "explanation": "Media organizations use exit polls to project winners and understand voter motivations."},
    {"id": 426, "unit": "Unit 4", "unitName": "American Political Ideologies and Beliefs", "concept": "Push Polls", "question": "A push poll is designed to:", "options": ["Gather accurate data", "Test polling equipment", "Influence respondents by asking leading or biased questions disguised as a survey", "Predict future elections"], "answer": "C", "explanation": "Push polls are a campaign tactic that spreads negative information under the guise of polling."},
    {"id": 427, "unit": "Unit 4", "unitName": "American Political Ideologies and Beliefs", "concept": "Benchmark Polls", "question": "Benchmark polls are taken:", "options": ["After an election", "Only on Election Day", "By interest groups", "Early in a campaign to assess a candidate's initial standing"], "answer": "D", "explanation": "Campaigns use benchmark polls to establish a baseline of support and plan strategy."},
    {"id": 428, "unit": "Unit 4", "unitName": "American Political Ideologies and Beliefs", "concept": "Tracking Polls", "question": "Tracking polls are conducted:", "options": ["Once per election", "Continuously throughout a campaign to monitor shifts in opinion", "Only in swing states", "By the government"], "answer": "B", "explanation": "Daily or frequent polling helps campaigns detect changes in voter sentiment."},
    {"id": 429, "unit": "Unit 4", "unitName": "American Political Ideologies and Beliefs", "concept": "Ideology and Age", "question": "Research shows that as people age, they tend to:", "options": ["Become somewhat more conservative on economic and social issues", "Become more liberal", "Stop voting", "Change parties every decade"], "answer": "A", "explanation": "While not universal, studies suggest older voters lean more conservative than younger ones."},
    {"id": 430, "unit": "Unit 4", "unitName": "American Political Ideologies and Beliefs", "concept": "Ideology and Education", "question": "Higher levels of education are generally associated with:", "options": ["Less political participation", "More liberal views on social issues and higher levels of political engagement", "Conservative economic views only", "No change in political views"], "answer": "B", "explanation": "Education correlates with greater tolerance and engagement, though economic views vary."},
    {"id": 431, "unit": "Unit 4", "unitName": "American Political Ideologies and Beliefs", "concept": "Ideology and Religion", "question": "Religious attendance is most strongly correlated with:", "options": ["Conservative positions, particularly on social issues", "Liberal social views", "No political views", "Libertarian ideology"], "answer": "A", "explanation": "Regular churchgoers tend to hold more conservative views on issues like abortion and same-sex marriage."},
    {"id": 432, "unit": "Unit 4", "unitName": "American Political Ideologies and Beliefs", "concept": "Ideology and Income", "question": "Higher income levels tend to correlate with:", "options": ["More liberal economic views", "No political preferences", "More conservative views on taxation and economic regulation", "Socialist ideology"], "answer": "C", "explanation": "Wealthier individuals often favor lower taxes and less government economic intervention."},
    {"id": 433, "unit": "Unit 4", "unitName": "American Political Ideologies and Beliefs", "concept": "Ideology and Race", "question": "African Americans have historically aligned with:", "options": ["The Republican Party", "Third parties", "The Democratic Party since the New Deal and civil rights era", "No political party"], "answer": "C", "explanation": "Since the 1960s, African Americans have overwhelmingly supported Democratic candidates."},
    {"id": 434, "unit": "Unit 4", "unitName": "American Political Ideologies and Beliefs", "concept": "Latino Political Views", "question": "Latino voters in the United States generally:", "options": ["Have diverse political views varying by national origin, but lean Democratic overall", "Vote as a monolithic bloc", "Always vote Republican", "Do not participate in elections"], "answer": "A", "explanation": "Cuban Americans historically lean Republican while Mexican Americans lean Democratic."},
    {"id": 435, "unit": "Unit 4", "unitName": "American Political Ideologies and Beliefs", "concept": "Priming", "question": "Media priming refers to:", "options": ["Printing newspapers", "The media's ability to influence the criteria by which people evaluate political figures", "Campaign advertising only", "Social media algorithms"], "answer": "B", "explanation": "By emphasizing certain issues, the media shapes which factors voters use to judge leaders."},
    {"id": 436, "unit": "Unit 4", "unitName": "American Political Ideologies and Beliefs", "concept": "Horse Race Journalism", "question": "Horse race journalism focuses on:", "options": ["Policy analysis", "Investigative reporting", "International news", "Campaign strategy, polls, and who is winning rather than substance"], "answer": "D", "explanation": "Critics argue this approach prioritizes entertainment over informing voters about policy."},
    {"id": 437, "unit": "Unit 4", "unitName": "American Political Ideologies and Beliefs", "concept": "Selective Exposure", "question": "Selective exposure means that people tend to:", "options": ["Watch all news sources equally", "Avoid all news", "Seek out media that confirms their existing political beliefs", "Only read print newspapers"], "answer": "C", "explanation": "This contributes to political polarization as people consume one-sided information."},
    {"id": 438, "unit": "Unit 4", "unitName": "American Political Ideologies and Beliefs", "concept": "Echo Chambers", "question": "Political echo chambers are problematic because they:", "options": ["Expose people to diverse viewpoints", "Increase voter turnout", "Improve media literacy", "Reinforce existing beliefs and contribute to political polarization"], "answer": "D", "explanation": "When people only hear views they agree with, they become more extreme and less tolerant of opposition."},
    {"id": 439, "unit": "Unit 4", "unitName": "American Political Ideologies and Beliefs", "concept": "Fiscal Conservative", "question": "A fiscal conservative generally supports:", "options": ["Higher taxes and more spending", "Lower taxes, reduced government spending, and balanced budgets", "Nationalized industries", "Unlimited government borrowing"], "answer": "B", "explanation": "Fiscal conservatives prioritize reducing the national debt and limiting government economic intervention."},
    {"id": 440, "unit": "Unit 4", "unitName": "American Political Ideologies and Beliefs", "concept": "Social Conservative", "question": "A social conservative typically supports:", "options": ["Progressive social policies", "Complete separation of church and state", "Traditional values, including opposition to abortion and support for religious liberty", "Legalizing all drugs"], "answer": "C", "explanation": "Social conservatives emphasize traditional family structures and moral values in public policy."},
    {"id": 441, "unit": "Unit 4", "unitName": "American Political Ideologies and Beliefs", "concept": "Progressive Ideology", "question": "Progressives generally advocate for:", "options": ["Maintaining the status quo", "Government action to address inequality, expand rights, and reform institutions", "Eliminating all government programs", "Returning to earlier policies"], "answer": "B", "explanation": "Modern progressives push for systemic changes to address social and economic disparities."},
    {"id": 442, "unit": "Unit 4", "unitName": "American Political Ideologies and Beliefs", "concept": "Neoconservatism", "question": "Neoconservatives are distinguished by their support for:", "options": ["Isolationism", "Reduced military spending", "Pacifism", "An assertive foreign policy and the promotion of democracy abroad"], "answer": "D", "explanation": "Neoconservatives advocate using American power, including military force, to spread democratic values."},
    {"id": 443, "unit": "Unit 4", "unitName": "American Political Ideologies and Beliefs", "concept": "Socialism in America", "question": "Democratic socialism in the United States advocates for:", "options": ["Government ownership of all property", "Expanded social programs within a democratic framework, such as universal healthcare", "Abolishing elections", "Complete free-market capitalism"], "answer": "B", "explanation": "American democratic socialists seek Nordic-style social programs while maintaining democratic governance."},
    {"id": 444, "unit": "Unit 4", "unitName": "American Political Ideologies and Beliefs", "concept": "Public Opinion on Healthcare", "question": "Public opinion polling consistently shows that Americans:", "options": ["Are divided on healthcare policy, with support varying by how the question is framed", "Unanimously support single-payer healthcare", "Never think about healthcare", "All oppose government involvement"], "answer": "A", "explanation": "Framing effects significantly influence poll results on healthcare policy."},
    {"id": 445, "unit": "Unit 4", "unitName": "American Political Ideologies and Beliefs", "concept": "Party Identification", "question": "Party identification is most strongly influenced by:", "options": ["Campaign advertising", "Family and early socialization experiences", "A single election", "Media consumption alone"], "answer": "B", "explanation": "Most people adopt the party affiliation of their parents, making it resistant to change."},
    {"id": 446, "unit": "Unit 4", "unitName": "American Political Ideologies and Beliefs", "concept": "Dealignment", "question": "Dealignment occurs when:", "options": ["Parties become stronger", "A new party replaces an old one", "Voters switch parties permanently", "Voters move away from party identification and become more independent"], "answer": "D", "explanation": "Dealignment reflects growing distrust of both major parties and an increase in independent voters."},
    {"id": 447, "unit": "Unit 4", "unitName": "American Political Ideologies and Beliefs", "concept": "Partisan Polarization", "question": "Partisan polarization has increased in recent decades, meaning that:", "options": ["Parties have become more moderate", "The ideological distance between Democrats and Republicans has grown significantly", "Third parties have gained power", "Voter turnout has decreased"], "answer": "B", "explanation": "Research shows increasing ideological homogeneity within parties and growing gaps between them."},
    {"id": 448, "unit": "Unit 4", "unitName": "American Political Ideologies and Beliefs", "concept": "Trust in Government", "question": "Trust in the federal government has generally:", "options": ["Increased steadily since 1960", "Remained constant", "Declined significantly since the 1960s, with occasional temporary increases", "Never been measured"], "answer": "C", "explanation": "Events like Vietnam, Watergate, and partisan conflict have eroded public trust over decades."},
    {"id": 449, "unit": "Unit 4", "unitName": "American Political Ideologies and Beliefs", "concept": "Political Knowledge", "question": "Research shows that most Americans:", "options": ["Have relatively low levels of political knowledge, especially about specific policies", "Are well-informed about politics", "Follow politics closely", "Can name all Supreme Court justices"], "answer": "A", "explanation": "Political knowledge varies widely and tends to be higher among older, wealthier, and more educated citizens."},
    {"id": 450, "unit": "Unit 4", "unitName": "American Political Ideologies and Beliefs", "concept": "Policy Mood", "question": "The concept of 'policy mood' refers to:", "options": ["Individual policy preferences", "Congressional voting patterns", "The general ideological direction of public opinion at a given time", "Presidential approval ratings"], "answer": "C", "explanation": "Policy mood shifts between liberal and conservative periods, influencing which policies are politically viable."},
    {"id": 451, "unit": "Unit 4", "unitName": "American Political Ideologies and Beliefs", "concept": "Crosscutting Cleavages", "question": "Crosscutting cleavages in public opinion occur when:", "options": ["An individual's group memberships pull them in different political directions", "Everyone agrees on every issue", "There is no political conflict", "Only one issue matters"], "answer": "A", "explanation": "A wealthy African American, for example, may face conflicting pressures on economic vs. social issues."},
    {"id": 452, "unit": "Unit 4", "unitName": "American Political Ideologies and Beliefs", "concept": "Wedge Issues", "question": "A wedge issue is designed to:", "options": ["Unite voters", "Reduce voter turnout", "Split the opposing party's coalition by highlighting a divisive topic", "Promote bipartisanship"], "answer": "C", "explanation": "Campaigns use wedge issues to peel off voters from the opposition by exploiting internal divisions."},
    {"id": 453, "unit": "Unit 4", "unitName": "American Political Ideologies and Beliefs", "concept": "Rally Around the Flag", "question": "The 'rally around the flag' effect occurs when:", "options": ["Voter turnout drops", "Congress passes a popular law", "Presidential approval ratings spike temporarily during international crises", "The economy improves"], "answer": "C", "explanation": "National security events tend to produce short-term increases in presidential approval."},
    {"id": 454, "unit": "Unit 4", "unitName": "American Political Ideologies and Beliefs", "concept": "Approval Ratings", "question": "Presidential approval ratings are most influenced by:", "options": ["The president's personality", "The first lady's popularity", "Weather patterns", "Economic conditions and major events"], "answer": "D", "explanation": "The economy is the strongest predictor of presidential approval over time."},
    {"id": 455, "unit": "Unit 4", "unitName": "American Political Ideologies and Beliefs", "concept": "Ideology and Gender", "question": "The gender gap in American politics shows that women are more likely than men to:", "options": ["Support Democratic candidates and favor government social programs", "Vote Republican", "Not vote", "Support military intervention"], "answer": "A", "explanation": "Women tend to prioritize healthcare, education, and social welfare, aligning them with Democratic positions."},
    {"id": 456, "unit": "Unit 4", "unitName": "American Political Ideologies and Beliefs", "concept": "Rural vs Urban Divide", "question": "The urban-rural divide in American politics shows that:", "options": ["Rural areas vote Democratic", "There is no geographic voting pattern", "Urban areas tend to vote Democratic while rural areas tend to vote Republican", "Suburban areas don't vote"], "answer": "C", "explanation": "This geographic sorting has become one of the most significant cleavages in American politics."},
    {"id": 457, "unit": "Unit 4", "unitName": "American Political Ideologies and Beliefs", "concept": "Social Media and Politics", "question": "Social media has changed American politics by:", "options": ["Reducing political engagement", "Having no effect on elections", "Replacing all traditional media", "Enabling rapid mobilization, direct communication, and the spread of misinformation"], "answer": "D", "explanation": "Social media amplifies voices and speeds information sharing but also facilitates polarization."},
    {"id": 458, "unit": "Unit 4", "unitName": "American Political Ideologies and Beliefs", "concept": "Civic Duty", "question": "The concept of civic duty suggests that citizens:", "options": ["Have no obligation to participate", "Have a responsibility to vote and participate in democratic processes", "Should only vote if they are informed", "Must join a political party"], "answer": "B", "explanation": "Civic duty is a significant motivator for voter turnout, especially in presidential elections."},
    {"id": 459, "unit": "Unit 4", "unitName": "American Political Ideologies and Beliefs", "concept": "Incumbency Advantage", "question": "Incumbents have an advantage in elections because of:", "options": ["Term limits", "Name recognition, access to campaign funds, and the ability to provide constituent services", "Being the challenger", "Running in open seats"], "answer": "B", "explanation": "Congressional incumbents win reelection over 90% of the time due to these structural advantages."},
    {"id": 460, "unit": "Unit 4", "unitName": "American Political Ideologies and Beliefs", "concept": "Mandate Theory", "question": "The mandate theory of elections holds that:", "options": ["A winning candidate has a mandate from the people to implement their proposed policies", "Elections are meaningless", "Only landslide victories matter", "Mandates only apply to presidents"], "answer": "A", "explanation": "Presidents often claim a mandate after winning, though the theory is debated by political scientists."},
    {"id": 461, "unit": "Unit 4", "unitName": "American Political Ideologies and Beliefs", "concept": "Culture War", "question": "The 'culture war' in American politics refers to:", "options": ["Deep divisions over social issues like abortion, LGBTQ+ rights, and religion in public life", "Military conflict", "Economic policy debates", "Foreign policy disagreements"], "answer": "A", "explanation": "These social and cultural disagreements have become central to partisan identity."},
    {"id": 462, "unit": "Unit 4", "unitName": "American Political Ideologies and Beliefs", "concept": "Libertarian vs Populist", "question": "The key difference between libertarians and populists is that:", "options": ["They agree on everything", "Populists are always liberal", "Libertarians support high taxes", "Libertarians want less government in both economic and social areas while populists want more in both"], "answer": "D", "explanation": "This distinction maps to the two-dimensional political spectrum beyond simple left-right."},
    {"id": 463, "unit": "Unit 4", "unitName": "American Political Ideologies and Beliefs", "concept": "Media Bias", "question": "Studies on media bias generally find that:", "options": ["All media is equally biased", "Bias varies by outlet, and consumers increasingly choose partisan sources that match their views", "There is no bias in any media", "Only TV news is biased"], "answer": "B", "explanation": "The proliferation of media choices allows consumers to self-select into ideological bubbles."},
    {"id": 464, "unit": "Unit 4", "unitName": "American Political Ideologies and Beliefs", "concept": "Federalism and Ideology", "question": "Conservative support for states' rights reflects the belief that:", "options": ["The federal government should control everything", "States should have no power", "State governments are closer to the people and better positioned to address local needs", "Only the Supreme Court should decide policy"], "answer": "C", "explanation": "Conservatives often invoke federalism to argue against federal regulation and mandates."},
    {"id": 465, "unit": "Unit 5", "unitName": "Political Participation", "concept": "Caucuses", "question": "A caucus differs from a primary election because it:", "options": ["Is a secret ballot", "Is run by the federal government", "Involves public discussion and voting at local meetings rather than a traditional ballot", "Only nominates vice presidents"], "answer": "C", "explanation": "Caucuses require greater time commitment and tend to attract more ideologically motivated participants."},
    {"id": 466, "unit": "Unit 5", "unitName": "Political Participation", "concept": "Frontloading", "question": "Frontloading in the presidential nomination process refers to:", "options": ["Delaying primaries", "States moving their primaries earlier in the calendar to gain more influence", "Loading ballots with extra candidates", "Adding more debate questions"], "answer": "B", "explanation": "States compete to hold early contests because early results shape momentum and media coverage."},
    {"id": 467, "unit": "Unit 5", "unitName": "Political Participation", "concept": "Superdelegates", "question": "Superdelegates in the Democratic Party are:", "options": ["Elected by voters in primaries", "Party leaders and elected officials who can vote for any candidate at the convention", "Required to follow primary results", "Also used by Republicans"], "answer": "B", "explanation": "Superdelegates give party elites some influence over the nomination process."},
    {"id": 468, "unit": "Unit 5", "unitName": "Political Participation", "concept": "Convention Bounce", "question": "A 'convention bounce' refers to:", "options": ["A temporary increase in a candidate's poll numbers after their party's national convention", "Physical activity at conventions", "A permanent shift in support", "Decreased media coverage"], "answer": "A", "explanation": "Conventions generate positive media coverage that typically produces a short-term polling boost."},
    {"id": 469, "unit": "Unit 5", "unitName": "Political Participation", "concept": "Swing States", "question": "Swing states receive disproportionate attention from campaigns because:", "options": ["They have the most electoral votes", "They always vote for the winner", "Their outcomes are uncertain and could go to either party", "They hold the earliest primaries"], "answer": "C", "explanation": "Candidates focus resources on competitive states where their effort can change the outcome."},
    {"id": 470, "unit": "Unit 5", "unitName": "Political Participation", "concept": "Soft Money", "question": "Soft money in campaign finance refers to:", "options": ["Direct donations to candidates", "Government campaign funding", "Funds raised by parties for 'party-building activities' that were largely unregulated before BCRA", "Small individual donations"], "answer": "C", "explanation": "The Bipartisan Campaign Reform Act of 2002 banned national party soft money."},
    {"id": 471, "unit": "Unit 5", "unitName": "Political Participation", "concept": "527 Organizations", "question": "527 organizations are:", "options": ["Part of the federal government", "Regulated by the FEC", "The same as Super PACs", "Tax-exempt groups that engage in political activities without directly advocating for candidates"], "answer": "D", "explanation": "527s can raise unlimited money for issue advocacy and voter mobilization."},
    {"id": 472, "unit": "Unit 5", "unitName": "Political Participation", "concept": "Dark Money", "question": "Dark money in politics refers to:", "options": ["Political spending by nonprofit organizations that do not disclose their donors", "Illegal campaign contributions", "Government slush funds", "Foreign campaign donations"], "answer": "A", "explanation": "501(c)(4) organizations can engage in politics without revealing who funds them."},
    {"id": 473, "unit": "Unit 5", "unitName": "Political Participation", "concept": "BCRA", "question": "The Bipartisan Campaign Reform Act (McCain-Feingold) primarily:", "options": ["Eliminated all campaign finance rules", "Created the Electoral College", "Banned soft money donations to national parties and restricted issue ads before elections", "Established term limits"], "answer": "C", "explanation": "BCRA addressed loopholes in campaign finance law, though Citizens United later weakened some provisions."},
    {"id": 474, "unit": "Unit 5", "unitName": "Political Participation", "concept": "Prospective Voting", "question": "Prospective voting occurs when voters:", "options": ["Look backward at past performance", "Make choices based on what they expect a candidate will do in the future", "Vote randomly", "Always support incumbents"], "answer": "B", "explanation": "Prospective voters evaluate candidates' policy proposals and promises."},
    {"id": 475, "unit": "Unit 5", "unitName": "Political Participation", "concept": "Party-Line Voting", "question": "Party-line voting has increased in recent years, which means:", "options": ["Voters split tickets more often", "Third parties are winning", "Turnout is declining", "More voters choose candidates of the same party for all offices on the ballot"], "answer": "D", "explanation": "Increased polarization has reduced split-ticket voting across most elections."},
    {"id": 476, "unit": "Unit 5", "unitName": "Political Participation", "concept": "Ballot Initiatives", "question": "A ballot initiative allows:", "options": ["Only legislators to propose laws", "Citizens to propose and vote directly on legislation or constitutional amendments", "The president to bypass Congress", "Judges to create new laws"], "answer": "B", "explanation": "Direct democracy mechanisms like initiatives give citizens a way to enact policy without legislators."},
    {"id": 477, "unit": "Unit 5", "unitName": "Political Participation", "concept": "Recall Elections", "question": "A recall election allows voters to:", "options": ["Remove an elected official from office before their term ends", "Elect new candidates only", "Choose Supreme Court justices", "Override a presidential veto"], "answer": "A", "explanation": "Recalls are available in some states and provide a check on elected officials between regular elections."},
    {"id": 478, "unit": "Unit 5", "unitName": "Political Participation", "concept": "Voter ID Laws", "question": "Supporters of voter ID laws argue they:", "options": ["Suppress minority votes", "Increase turnout", "Prevent voter fraud and protect election integrity", "Are unconstitutional"], "answer": "C", "explanation": "The debate centers on election security versus concerns about disenfranchising eligible voters."},
    {"id": 479, "unit": "Unit 5", "unitName": "Political Participation", "concept": "Early Voting", "question": "Early voting and mail-in ballots have:", "options": ["Decreased voter access", "Had no effect on turnout", "Been banned in most states", "Expanded access to voting and increased convenience for many citizens"], "answer": "D", "explanation": "These methods reduce barriers to voting, particularly for working people and those with limited mobility."},
    {"id": 480, "unit": "Unit 5", "unitName": "Political Participation", "concept": "Motor Voter Act", "question": "The National Voter Registration Act (Motor Voter) requires:", "options": ["All citizens to vote", "Mandatory voting", "Automatic citizenship for voters", "States to offer voter registration when citizens apply for driver's licenses"], "answer": "D", "explanation": "The law simplified registration by integrating it with common government interactions."},
    {"id": 481, "unit": "Unit 5", "unitName": "Political Participation", "concept": "Socioeconomic Status and Voting", "question": "Voter turnout tends to increase with:", "options": ["Lower income", "Younger age", "Rural residence", "Higher income, education, and age"], "answer": "D", "explanation": "Socioeconomic factors are among the strongest predictors of political participation."},
    {"id": 482, "unit": "Unit 5", "unitName": "Political Participation", "concept": "Rational Ignorance", "question": "Rational ignorance occurs when citizens:", "options": ["Are uninformed due to laziness", "Are prohibited from learning", "Only watch one news source", "Decide that the cost of becoming informed outweighs the expected benefit"], "answer": "D", "explanation": "Since one vote rarely decides an election, some citizens rationally choose not to invest in political knowledge."},
    {"id": 483, "unit": "Unit 5", "unitName": "Political Participation", "concept": "Free Rider Problem", "question": "The free rider problem in interest group politics occurs when:", "options": ["People benefit from a group's efforts without contributing to it", "Everyone pays dues", "Groups have too many members", "All members participate equally"], "answer": "A", "explanation": "This challenge makes it harder for large groups to organize effectively."},
    {"id": 484, "unit": "Unit 5", "unitName": "Political Participation", "concept": "Selective Benefits", "question": "Interest groups overcome the free rider problem by offering:", "options": ["Selective benefits available only to members, such as discounts or publications", "Nothing to members", "Government contracts", "Tax exemptions to non-members"], "answer": "A", "explanation": "Material, solidary, and purposive incentives encourage individuals to join and contribute."},
    {"id": 485, "unit": "Unit 5", "unitName": "Political Participation", "concept": "Grassroots Lobbying", "question": "Grassroots lobbying involves:", "options": ["Hiring professional lobbyists", "Filing lawsuits", "Mobilizing ordinary citizens to contact their representatives about an issue", "Running campaign ads"], "answer": "C", "explanation": "Interest groups use grassroots campaigns to demonstrate broad public support for their positions."},
    {"id": 486, "unit": "Unit 5", "unitName": "Political Participation", "concept": "Revolving Door", "question": "The 'revolving door' in politics refers to:", "options": ["The movement of personnel between government positions and private sector lobbying jobs", "Turnstiles at government buildings", "Term limits", "Frequent elections"], "answer": "A", "explanation": "Critics argue this creates conflicts of interest and gives special interests undue influence."},
    {"id": 487, "unit": "Unit 5", "unitName": "Political Participation", "concept": "Electioneering", "question": "Electioneering by interest groups includes:", "options": ["Only donating money", "Filing amicus briefs only", "Writing legislation", "Endorsing candidates, running ads, mobilizing voters, and contributing to campaigns"], "answer": "D", "explanation": "Interest groups use multiple strategies to influence election outcomes."},
    {"id": 488, "unit": "Unit 5", "unitName": "Political Participation", "concept": "Plurality vs Majority", "question": "In a plurality election system, the winner:", "options": ["Needs only the most votes, not necessarily a majority", "Must get over 50% of the vote", "Must win every state", "Is chosen by the Electoral College"], "answer": "A", "explanation": "Most U.S. elections use plurality (first-past-the-post), which disadvantages third parties."},
    {"id": 489, "unit": "Unit 5", "unitName": "Political Participation", "concept": "Proportional Representation", "question": "Proportional representation systems tend to produce:", "options": ["Multi-party systems where seats are allocated based on vote share", "Two-party systems", "One-party rule", "No political parties"], "answer": "A", "explanation": "PR systems give smaller parties representation, unlike winner-take-all systems."},
    {"id": 490, "unit": "Unit 5", "unitName": "Political Participation", "concept": "National Party Committees", "question": "The national party committees (DNC and RNC) primarily:", "options": ["Write legislation", "Confirm judicial nominees", "Coordinate campaign strategy, fundraising, and party messaging", "Govern states"], "answer": "C", "explanation": "National committees play a crucial role in supporting candidates and building party infrastructure."},
    {"id": 491, "unit": "Unit 5", "unitName": "Political Participation", "concept": "Presidential Coattails", "question": "The 'coattail effect' refers to:", "options": ["The ability of a popular presidential candidate to help other party candidates win", "Fashion at political events", "Always winning the popular vote", "Third-party success"], "answer": "A", "explanation": "Strong presidential candidates can boost turnout and support for down-ballot party members."},
    {"id": 492, "unit": "Unit 5", "unitName": "Political Participation", "concept": "Divided Government", "question": "Divided government occurs when:", "options": ["One party controls everything", "Different parties control the presidency and at least one chamber of Congress", "The Supreme Court disagrees with Congress", "States oppose federal policy"], "answer": "B", "explanation": "Divided government can lead to gridlock but also forces compromise between parties."},
    {"id": 493, "unit": "Unit 5", "unitName": "Political Participation", "concept": "Malapportionment", "question": "Malapportionment refers to:", "options": ["Equal district populations", "Gerrymandering", "Voter suppression", "Unequal representation caused by districts with significantly different population sizes"], "answer": "D", "explanation": "Baker v. Carr and Reynolds v. Sims addressed malapportionment by requiring equal population districts."},
    {"id": 494, "unit": "Unit 5", "unitName": "Political Participation", "concept": "Packing and Cracking", "question": "In gerrymandering, 'packing' and 'cracking' refer to:", "options": ["Moving people between districts", "Increasing voter turnout", "Concentrating opposition voters in few districts (packing) or spreading them thin (cracking)", "Eliminating districts"], "answer": "C", "explanation": "These techniques allow map-drawers to dilute the electoral power of opposing party voters."},
    {"id": 495, "unit": "Unit 5", "unitName": "Political Participation", "concept": "Midterm Election Patterns", "question": "The president's party typically loses seats in midterm elections because:", "options": ["The president campaigns too much", "Lower turnout benefits the opposition and voters often express dissatisfaction with the ruling party", "Midterms always favor Republicans", "The Constitution requires it"], "answer": "B", "explanation": "This pattern has held in most midterm elections throughout American history."},
